export type VoiceSteeringClientClassification =
  | "on_topic_additive"
  | "constraint"
  | "correction"
  | "off_topic_new_goal"
  | "cancel_or_stop"
  | "ambient";

export type VoiceSteeringClientRequest = {
  thread_id: string;
  turn_id: string;
  expected_turn_id: string;
  transcript_text: string;
  source: "voice_capture";
  timing: "during_reasoning" | "during_tool_call";
  classification: VoiceSteeringClientClassification;
  queue_decision:
    | "queued_for_safe_boundary"
    | "deferred_to_new_turn"
    | "cancel_requested"
    | "ambient_ignored";
  evidence_refs: string[];
  reason_codes: string[];
};

export function classifyVoiceSteeringClientTranscript(transcript: string): {
  classification: VoiceSteeringClientClassification;
  queueDecision: VoiceSteeringClientRequest["queue_decision"];
  reasonCodes: string[];
} {
  const text = transcript.trim();
  if (!text || text.length < 3) {
    return {
      classification: "ambient",
      queueDecision: "ambient_ignored",
      reasonCodes: ["too_short_or_empty"],
    };
  }
  if (/\b(stop|cancel|abort|pause|never mind|nevermind)\b/i.test(text)) {
    return {
      classification: "cancel_or_stop",
      queueDecision: "cancel_requested",
      reasonCodes: ["explicit_cancel_phrase"],
    };
  }
  if (/\b(actually|correction|i meant|not that|use .* instead)\b/i.test(text)) {
    return {
      classification: "correction",
      queueDecision: "queued_for_safe_boundary",
      reasonCodes: ["correction_phrase"],
    };
  }
  if (/\b(do not|don't|dont|only|never|make sure|must|instead)\b/i.test(text)) {
    return {
      classification: "constraint",
      queueDecision: "queued_for_safe_boundary",
      reasonCodes: ["constraint_phrase"],
    };
  }
  if (/\b(also|while you|check|look at|remember|include)\b/i.test(text)) {
    return {
      classification: "on_topic_additive",
      queueDecision: "queued_for_safe_boundary",
      reasonCodes: ["additive_phrase"],
    };
  }
  return {
    classification: "off_topic_new_goal",
    queueDecision: "deferred_to_new_turn",
    reasonCodes: ["default_active_turn_new_goal"],
  };
}

export function buildVoiceSteeringClientRequest(args: {
  threadId: string;
  turnId: string;
  expectedTurnId?: string | null;
  transcriptText: string;
  timing: "during_reasoning" | "during_tool_call";
  evidenceRefs?: string[];
}): VoiceSteeringClientRequest {
  const classified = classifyVoiceSteeringClientTranscript(args.transcriptText);
  return {
    thread_id: args.threadId,
    turn_id: args.turnId,
    expected_turn_id: args.expectedTurnId?.trim() || args.turnId,
    transcript_text: args.transcriptText.trim(),
    source: "voice_capture",
    timing: args.timing,
    classification: classified.classification,
    queue_decision: classified.queueDecision,
    evidence_refs: Array.from(new Set(args.evidenceRefs ?? [])),
    reason_codes: classified.reasonCodes,
  };
}

export function isVoiceSteeringDuringToolCall(events: Array<{ tool?: unknown; status?: unknown; type?: unknown }>): boolean {
  return events.some((event) => {
    const status = String(event.status ?? "").toLowerCase();
    const type = String(event.type ?? "").toLowerCase();
    const tool = String(event.tool ?? "").trim();
    return Boolean(tool) && (
      status === "running" ||
      status === "queued" ||
      type.includes("tool") ||
      type.includes("action")
    );
  });
}

function isExplicitVoiceAskTurnCandidate(transcript: string): boolean {
  const text = transcript.trim();
  if (!text) return false;
  if (shouldDispatchReasoningAttempt(text)) return true;
  if (isSimpleConversationTurnCandidate(text)) return true;
  return /\b(?:ask|question|tell me|explain|summari[sz]e|review|what|why|how|can you|could you|please|send|submit)\b/i.test(
    text,
  );
}

export function evaluateVoiceAutoDispatchGovernance(args: {
  transcript: string;
  micArmState: MicArmState;
  confidence?: number | null;
  dispatchState?: VoiceConfirmedTurn["dispatchState"];
  interpreterDispatchState?: VoiceConfirmedTurn["interpreterDispatchState"];
  possibleTtsEcho?: boolean;
  forceReasoningAfterWorkstation?: boolean;
  queueDepth?: number;
  activeDispatchCount?: number;
  maxAutoDispatchPerWindow?: number;
  maxQueueDepth?: number;
}): VoiceAutoDispatchGovernance {
  const transcript = args.transcript.trim();
  const confidence = typeof args.confidence === "number" && Number.isFinite(args.confidence) ? args.confidence : null;
  const queueDepth = Math.max(0, Math.floor(args.queueDepth ?? 0));
  const activeDispatchCount = Math.max(0, Math.floor(args.activeDispatchCount ?? 0));
  const maxAutoDispatchPerWindow = Math.max(
    1,
    Math.floor(args.maxAutoDispatchPerWindow ?? HELIX_VOICE_AUTO_DISPATCH_MAX_PER_MINUTE),
  );
  const maxQueueDepth = Math.max(1, Math.floor(args.maxQueueDepth ?? HELIX_VOICE_TRANSCRIBE_QUEUE_MAX));
  const candidateDispatchHint =
    args.forceReasoningAfterWorkstation === true || isExplicitVoiceAskTurnCandidate(transcript);
  let reason: VoiceAutoDispatchGovernanceReason = "admitted_explicit_user_turn";
  let admitted = true;
  if (!transcript) {
    admitted = false;
    reason = "empty_transcript";
  } else if (args.micArmState !== "on") {
    admitted = false;
    reason = "mic_not_armed";
  } else if (args.possibleTtsEcho === true) {
    admitted = false;
    reason = "possible_tts_echo";
  } else if (args.dispatchState === "blocked" || args.interpreterDispatchState === "blocked") {
    admitted = false;
    reason = "blocked_interpreter_dispatch";
  } else if (confidence !== null && confidence < HELIX_VOICE_AUTO_DISPATCH_CONFIDENCE_FLOOR) {
    admitted = false;
    reason = "confidence_below_auto_dispatch_floor";
  } else if (queueDepth >= maxQueueDepth) {
    admitted = false;
    reason = "queue_backpressure";
  } else if (activeDispatchCount >= maxAutoDispatchPerWindow) {
    admitted = false;
    reason = "auto_dispatch_budget_exceeded";
  } else if (!candidateDispatchHint) {
    admitted = false;
    reason = "observe_only_by_default";
  } else if (args.forceReasoningAfterWorkstation === true) {
    reason = "admitted_forced_reasoning";
  }
  return {
    schema: "helix.voice_auto_dispatch_governance.v1",
    admitted,
    reason,
    candidateDispatchHint,
    queueDepth,
    activeDispatchCount,
    confidence,
    assistant_answer: false,
    raw_content_included: false,
    output_authority: "admission_trace",
    instruction_authority: "none",
  };
}

export type VoiceAutoSpeakTask = {
  key: string;
  kind: VoicePlaybackUtteranceKind;
  turnKey: string;
  revision: number;
  text: string;
  traceId?: string;
  eventId: string;
  authority?: VoicePlaybackIntentAuthority;
  source?: VoicePlaybackIntentSource;
  replyId?: string;
  allowMicOffPlayback?: boolean;
  interimVoiceRequestId?: string;
  interimVoiceReceiptId?: string;
  interimVoiceReceiptKey?: string;
  interimVoiceCalloutKind?: string;
  briefSource?: "llm" | "none";
  finalSource?: "normal_reasoning" | "strict_gate_override";
};

export type VoicePlaybackUtteranceIntent = {
  kind: VoicePlaybackUtteranceKind;
  authority: VoicePlaybackIntentAuthority;
  turnKey: string;
  revision: number;
  text: string;
  traceId?: string;
  eventId: string;
  replyId?: string;
  allowMicOffPlayback?: boolean;
  interimVoiceRequestId?: string;
  interimVoiceReceiptId?: string;
  interimVoiceReceiptKey?: string;
  interimVoiceCalloutKind?: string;
  source: VoicePlaybackIntentSource;
  briefSource?: "llm" | "none";
  finalSource?: "normal_reasoning" | "strict_gate_override";
};

export function buildManualReadAloudVoiceIntent(input: {
  text: string;
  replyId: string;
  traceId?: string | null;
  turnKey?: string | null;
}): VoicePlaybackUtteranceIntent {
  const turnKey = input.turnKey?.trim() || `manual:${input.replyId}`;
  return {
    kind: "manual_read_aloud",
    authority: "final",
    turnKey,
    revision: 1,
    text: input.text,
    traceId: input.traceId?.trim() || undefined,
    eventId: input.replyId,
    replyId: input.replyId,
    source: "manual",
  };
}

export function mapVoicePlaybackIntentToTask(intent: VoicePlaybackUtteranceIntent): VoiceAutoSpeakTask {
  return {
    key: buildVoiceAutoSpeakUtteranceId([
      intent.kind,
      intent.traceId ?? intent.turnKey,
      intent.eventId,
      intent.replyId,
    ]),
    kind: intent.kind,
    turnKey: intent.turnKey,
    revision: intent.revision,
    text: intent.text,
    traceId: intent.traceId,
    eventId: intent.eventId,
    authority: intent.authority,
    source: intent.source,
    replyId: intent.replyId,
    allowMicOffPlayback: intent.allowMicOffPlayback,
    interimVoiceRequestId: intent.interimVoiceRequestId,
    interimVoiceReceiptId: intent.interimVoiceReceiptId,
    interimVoiceReceiptKey: intent.interimVoiceReceiptKey,
    interimVoiceCalloutKind: intent.interimVoiceCalloutKind,
    briefSource: intent.briefSource,
    finalSource: intent.finalSource,
  };
}

type InterimVoiceCalloutKind =
  | "immediate_ack"
  | "tool_started"
  | "tool_progress"
  | "tool_result"
  | "waiting_for_evidence"
  | "memory_pressure"
  | "clarifying_status"
  | "steering_ack"
  | "translation_relay";

export type InterimVoiceCalloutPlaybackIntent = VoicePlaybackUtteranceIntent & {
  requestId: string;
  receiptId: string;
  receiptKey: string;
  calloutKind: InterimVoiceCalloutKind;
};

const INTERIM_VOICE_CALLOUT_TOOL_RESULT_SCHEMA = "helix.interim_voice_callout_tool_result.v1";

const INTERIM_VOICE_CALLOUT_KINDS = new Set<InterimVoiceCalloutKind>([
  "immediate_ack",
  "tool_started",
  "tool_progress",
  "tool_result",
  "waiting_for_evidence",
  "memory_pressure",
  "clarifying_status",
  "steering_ack",
  "translation_relay",
]);

const INTERIM_VOICE_CALLOUT_PLAYABLE_STATUSES = new Set([
  "awaiting_client_playback",
  "queued",
  "delivered",
]);

const readInterimVoiceRecord = (value: unknown): Record<string, unknown> | null =>
  value && typeof value === "object" && !Array.isArray(value)
    ? value as Record<string, unknown>
    : null;

const readInterimVoiceString = (value: unknown): string | null =>
  typeof value === "string" && value.trim() ? value.trim() : null;

const isInterimVoiceAuthoritySafe = (record: Record<string, unknown>): boolean =>
  record.assistant_answer === false &&
  record.terminal_eligible === false &&
  record.raw_content_included === false;

const readInterimVoiceCalloutKind = (value: unknown): InterimVoiceCalloutKind | null => {
  const kind = readInterimVoiceString(value);
  return kind && INTERIM_VOICE_CALLOUT_KINDS.has(kind as InterimVoiceCalloutKind)
    ? kind as InterimVoiceCalloutKind
    : null;
};

const buildInterimVoiceReceiptPlaybackIntent = (
  value: unknown,
): InterimVoiceCalloutPlaybackIntent | null => {
  const result = readInterimVoiceRecord(value);
  if (!result || result.schema !== INTERIM_VOICE_CALLOUT_TOOL_RESULT_SCHEMA) return null;
  const request = readInterimVoiceRecord(result.request);
  const receipt = readInterimVoiceRecord(result.receipt);
  if (!request || !receipt) return null;
  if (!isInterimVoiceAuthoritySafe(request) || !isInterimVoiceAuthoritySafe(receipt)) return null;
  if (request.authority !== "provisional") return null;
  const status = readInterimVoiceString(receipt.status);
  if (!status || !INTERIM_VOICE_CALLOUT_PLAYABLE_STATUSES.has(status)) return null;
  const calloutKind = readInterimVoiceCalloutKind(request.kind);
  if (!calloutKind) return null;
  const text = readInterimVoiceString(request.text);
  const turnKey = readInterimVoiceString(request.turnId) ?? readInterimVoiceString(request.turn_id);
  const requestId = readInterimVoiceString(request.requestId) ?? readInterimVoiceString(request.request_id);
  const receiptId = readInterimVoiceString(receipt.receiptId) ?? readInterimVoiceString(receipt.receipt_id);
  if (!text || !turnKey || !requestId || !receiptId) return null;
  const delivery = readInterimVoiceRecord(receipt.delivery);
  const utteranceId = readInterimVoiceString(delivery?.utteranceId) ?? readInterimVoiceString(delivery?.utterance_id);
  const receiptKey = utteranceId ?? receiptId;
  const playbackKind =
    readInterimVoiceString(request.voicePlaybackKind) === "translation_relay" || calloutKind === "translation_relay"
      ? "translation_relay"
      : "tool_receipt";
  return {
    kind: playbackKind,
    authority: "provisional",
    source: "agent_loop",
    turnKey,
    revision: 1,
    text,
    traceId: turnKey,
    eventId: receiptId,
    requestId,
    receiptId,
    receiptKey,
    calloutKind,
    interimVoiceRequestId: requestId,
    interimVoiceReceiptId: receiptId,
    interimVoiceReceiptKey: receiptKey,
    interimVoiceCalloutKind: calloutKind,
  };
};

export function collectInterimVoiceCalloutPlaybackIntents(input: {
  artifacts: unknown[];
  spokenReceiptKeys?: Iterable<string>;
  spokenImmediateAckTurnKeys?: Iterable<string>;
}): InterimVoiceCalloutPlaybackIntent[] {
  const spokenReceiptKeys = new Set(input.spokenReceiptKeys ?? []);
  const spokenImmediateAckTurnKeys = new Set(input.spokenImmediateAckTurnKeys ?? []);
  const emittedReceiptKeys = new Set<string>();
  const emittedImmediateAckTurnKeys = new Set<string>();
  const intents: InterimVoiceCalloutPlaybackIntent[] = [];
  const visited = new WeakSet<object>();

  const visit = (value: unknown) => {
    if (!value || typeof value !== "object") return;
    if (visited.has(value)) return;
    visited.add(value);
    const intent = buildInterimVoiceReceiptPlaybackIntent(value);
    if (intent) {
      const receiptKnown =
        spokenReceiptKeys.has(intent.receiptKey) ||
        spokenReceiptKeys.has(intent.receiptId) ||
        emittedReceiptKeys.has(intent.receiptKey) ||
        emittedReceiptKeys.has(intent.receiptId);
      const immediateAckKnown =
        intent.calloutKind === "immediate_ack" &&
        (spokenImmediateAckTurnKeys.has(intent.turnKey) || emittedImmediateAckTurnKeys.has(intent.turnKey));
      if (!receiptKnown && !immediateAckKnown) {
        intents.push(intent);
        emittedReceiptKeys.add(intent.receiptKey);
        emittedReceiptKeys.add(intent.receiptId);
        if (intent.calloutKind === "immediate_ack") {
          emittedImmediateAckTurnKeys.add(intent.turnKey);
        }
      }
    }
    if (Array.isArray(value)) {
      value.forEach(visit);
      return;
    }
    for (const child of Object.values(value as Record<string, unknown>)) {
      visit(child);
    }
  };

  input.artifacts.forEach(visit);
  return intents;
}

function isManualVoicePlaybackUtterance(utterance: Pick<VoicePlaybackUtterance, "kind" | "source"> | null | undefined): boolean {
  return utterance?.kind === "manual_read_aloud" || utterance?.source === "manual";
}

function isInterimVoicePlaybackUtteranceKind(kind: VoicePlaybackUtteranceKind): boolean {
  return kind === "tool_receipt" || kind === "translation_relay";
}

function canPlayVoiceUtteranceWithMicOff(
  utterance: Pick<VoicePlaybackUtterance, "kind" | "source" | "allowMicOffPlayback"> | null | undefined,
): boolean {
  return isManualVoicePlaybackUtterance(utterance) || utterance?.allowMicOffPlayback === true;
}

function isMissionVoiceOutputModeEnabled(voiceMode: string | null | undefined): boolean {
  return voiceMode === "normal";
}

