export type TranscriptConfirmPolicyReason =
  | "dispatch_blocked"
  | "pivot_low_confidence"
  | "translation_uncertain_without_pivot"
  | "dispatch_not_confirm"
  | "invalid_confidence"
  | "low_audio_quality"
  | "live_activity"
  | "eligible";

