function sanitizeConversationBriefTextForVoice(value: string, maxChars = 560): string {
  const normalized = value
    .replace(/\?/g, ".")
    .replace(/\s+/g, " ")
    .replace(/\.\.+/g, ".")
    .trim();
  return clipText(normalized, maxChars);
}

function normalizeBriefComparableText(value: string): string {
  return value
    .toLowerCase()
    .replace(/[^a-z0-9\s]/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function isBriefEchoingTranscript(briefText: string, transcript: string): boolean {
  const brief = normalizeBriefComparableText(briefText);
  const source = normalizeBriefComparableText(transcript);
  if (!brief || !source) return false;
  if (brief === source) return true;
  if (brief.startsWith(source) && brief.length <= source.length + 24) return true;
  return false;
}

function laneLabelForConversationMode(mode?: "observe" | "act" | "verify" | "clarify"): string {
  if (mode === "verify") return "verification";
  if (mode === "act") return "action";
  if (mode === "observe") return "observe";
  if (mode === "clarify") return "clarify";
  return "reasoning";
}

function normalizeConversationRouteReasonCode(reasonCode?: string | null): string | null {
  const trimmed = reasonCode?.trim().toLowerCase();
  return trimmed ? trimmed : null;
}

function normalizeVoiceFailureReasonText(reason?: string | null): string | null {
  const trimmed = reason?.trim();
  if (!trimmed) return null;
  const normalized = trimmed.toUpperCase();
  const messageMap: Array<{ pattern: RegExp; text: string }> = [
    {
      pattern: /\bDESKTOP_JOINT_SCOPE_REQUIRED\b/,
      text: "desktop joint scope is required before this run can execute",
    },
    {
      pattern: /\bCALIBRATION_STATE_INCOMPLETE\b/,
      text: "calibration is incomplete for this run",
    },
    {
      pattern: /\bIMU_BASELINE_NOT_CONFIGURED\b/,
      text: "the IMU baseline is not configured for this run",
    },
    {
      pattern: /\bESTOP_NOT_READY\b/,
      text: "the emergency stop state is not ready for this run",
    },
    {
      pattern: /\bFORBIDDEN_CONTROL_PATH\b/,
      text: "the request targets restricted actuator-level controls",
    },
    {
      pattern: /\bEVIDENCE_CONTRACT_FIELD_MISSING\b/,
      text: "required evidence fields were missing",
    },
    {
      pattern: /\bTOOL_NOT_ALLOWED\b/,
      text: "the requested tool is not allowed in this lane",
    },
    {
      pattern: /\bGENERIC_COLLAPSE\b/,
      text: "the reasoning stack could not complete the run",
    },
    {
      pattern: /\bHELIX_ASK_FAILED_400\b/,
      text: "a request gate blocked this run",
    },
    {
      pattern: /\bHELIX_ASK_FAILED_403\b/,
      text: "access policy blocked this run",
    },
    {
      pattern: /\bREASONING_TIMEOUT\b|\bHELIX_ASK_TIMEOUT\b|\bREQUEST TIMED OUT\b/,
      text: "the run timed out before completion",
    },
  ];
  for (const entry of messageMap) {
    if (entry.pattern.test(normalized)) {
      return entry.text;
    }
  }
  if (/\bABORT|CANCEL|INTERRUPT|SUPERSEDE\b/i.test(trimmed)) {
    return "the run was interrupted by a newer turn";
  }
  return null;
}

function isReasoningTimeoutReason(reason?: string | null): boolean {
  const trimmed = reason?.trim();
  if (!trimmed) return false;
  return /\breasoning_timeout\b|\bhelix_ask_timeout\b|\brequest timed out\b|\btimed out\b/i.test(
    trimmed,
  );
}

function isVoiceTurnSupersededReason(reason?: string | null): boolean {
  const trimmed = reason?.trim();
  if (!trimmed) return false;
  if (normalizeVoiceFailureReasonText(trimmed) === "the run was interrupted by a newer turn") {
    return true;
  }
  return /\bvoice_turn_(continuation_merged|response_stale|superseded_by_newer_attempt|superseded_by_newer_intent_revision)\b/i.test(
    trimmed,
  );
}

type AskLocalOptions = Parameters<typeof askLocal>[1];
type AskLocalMode = NonNullable<AskLocalOptions>["mode"];
type AskLocalResult = Awaited<ReturnType<typeof askLocal>>;

const AGIBOT_PREFLIGHT_SCOPE_ERROR_RE =
  /\bDESKTOP_JOINT_SCOPE_REQUIRED\b|desktop joint scope is required|mission interface blocked by bring-up preflight gate|preflight_gate/i;

export function isAgibotPreflightScopeError(error: unknown): boolean {
  if (!error) return false;
  const rawMessage =
    typeof error === "string"
      ? error
      : error instanceof Error
        ? error.message
        : typeof (error as { message?: unknown }).message === "string"
          ? String((error as { message?: unknown }).message)
          : "";
  if (!rawMessage) return false;
  return AGIBOT_PREFLIGHT_SCOPE_ERROR_RE.test(rawMessage);
}

type AskLocalWithFallbackResult = {
  response: AskLocalResult;
  downgradedFromMode?: AskLocalMode;
  bypassedMultilangGate?: boolean;
};

type RunAskOptions = {
  bypassWorkstationDispatch?: boolean;
  forceReasoningDispatch?: boolean;
  suppressWorkstationPayloadActions?: boolean;
  answerContract?: HelixAskAnswerContract;
  routeMetadata?: HelixAskRouteMetadata;
  contextMode?: "attached" | "isolated";
  skipContextChooser?: boolean;
  visualCapability?: Record<string, unknown>;
  visualEvidence?: Record<string, unknown>;
  imageAttachment?: HelixAskImageAttachment;
};

type AskContextChooserState = {
  id: string;
  question: string;
  capsuleIds?: string[];
  options?: RunAskOptions;
  autoContextMode?: "attached" | "isolated";
  autoContextReason?: string;
};

type HelixAskImageAttachment = {
  id: string;
  fileName: string;
  mimeType: string;
  sizeBytes: number;
  imageBase64?: string | null;
  imageRef?: string | null;
  evidenceRef?: string | null;
  previewUrl: string;
  status: "ready" | "error";
  error?: string | null;
};

const HELIX_ASK_VISUAL_SURFACE_PROMPT_PATTERN =
  /\b(?:image|screenshot|screen\s*share|screen\s*sharing|screen|display|window|tab|picture|photo|attached|visual|visible|from this|from the image|hotbar|inventory|chest|container)\b/i;
const HELIX_ASK_AMBIGUOUS_LIVE_CONTEXT_PROMPT_PATTERN = /\blive\s+(?:source|answer)\b/i;
const HELIX_ASK_WORKSTATION_LIVE_CONTEXT_PROMPT_PATTERN =
  /\b(?:(?:scientific\s+)?calculator|equation|prime|computation|workstation)\b[\s\S]{0,80}\blive\s+(?:source|stream|answer)\b|\blive\s+(?:source|stream|answer)\b[\s\S]{0,80}\b(?:(?:scientific\s+)?calculator|equation|prime|computation|workstation)\b/i;

const isHelixAskVisualPrompt = (value: string): boolean => {
  const normalized = value.trim();
  if (!normalized) return false;
  if (HELIX_ASK_VISUAL_SURFACE_PROMPT_PATTERN.test(normalized)) return true;
  if (!HELIX_ASK_AMBIGUOUS_LIVE_CONTEXT_PROMPT_PATTERN.test(normalized)) return false;
  return !HELIX_ASK_WORKSTATION_LIVE_CONTEXT_PROMPT_PATTERN.test(normalized);
};

const HELIX_ASK_REPO_CODE_EVIDENCE_PROMPT_PATTERN =
  /\b(?:repo(?:sitory)?|code|source\s+(?:file|path|tree)|file\s+paths?|line-backed|line\s+(?:number|numbers|source|sources)|cite\s+(?:exact\s+)?(?:file|path|source)|where\s+is\s+(?:that\s+)?(?:enforced|defined|declared|implemented|wired)|contract|schema|module|endpoint|route|symbol|export(?:s|ed)?|import(?:s|ed)?|requestedLaneSchema|server\/|client\/|shared\/|docs\/|[A-Za-z0-9_-]+\.(?:ts|tsx|js|jsx|md|json|py))\b/i;

const isRepoCodeEvidencePrompt = (question: string): boolean =>
  HELIX_ASK_REPO_CODE_EVIDENCE_PROMPT_PATTERN.test(question.trim());

const resolveAskContextChooserAutoMode = (question: string): {
  mode: "attached" | "isolated";
  reason: string;
} => {
  const normalized = question.trim();
  if (
    isRepoCodeEvidencePrompt(normalized) &&
    !isHelixAskVisualPrompt(normalized)
  ) {
    return {
      mode: "isolated",
      reason: "repo_code_evidence_prompt",
    };
  }
  return {
    mode: "attached",
    reason: "workspace_context_reasoning_prompt",
  };
};

const HELIX_VISUAL_DIAGNOSTIC_SUMMARY_PATTERN =
  /\b(?:visual\s+frame\s+was\s+recorded|no\s+configured\s+vision\s+provider|configured\s+vision\s+provider\s+did\s+not\s+return|did\s+not\s+return\s+an?\s+image\s+description|did\s+not\s+produce\s+usable\s+visual\s+evidence|waiting\s+for\s+image\s+recognition|vision_provider_[a-z_]+|provider\s+(?:missing|failed|unavailable)|analysis_failed|capture\s+(?:and\s+analyze\s+)?(?:a\s+)?fresh\s+frame|recover\s+the\s+vision\s+provider)\b/i;

function readVisualEvidenceSummary(record: Record<string, unknown> | null | undefined): string | null {
  const evidence = record?.evidence;
  const evidenceRecord = evidence && typeof evidence === "object" ? (evidence as Record<string, unknown>) : null;
  const directSummary = typeof record?.summary === "string" ? record.summary.trim() : "";
  const nestedSummary = typeof evidenceRecord?.summary === "string" ? evidenceRecord.summary.trim() : "";
  return directSummary || nestedSummary || null;
}

function isDiagnosticVisualEvidence(record: Record<string, unknown> | null | undefined): boolean {
  const summary = readVisualEvidenceSummary(record);
  return Boolean(summary && HELIX_VISUAL_DIAGNOSTIC_SUMMARY_PATTERN.test(summary));
}

function validateHelixAskImageAttachmentForSubmit(
  attachment: HelixAskImageAttachment | null | undefined,
): HelixAttachmentCommitCheck | null {
  if (!attachment) return null;
  const hasImageBase64 = typeof attachment.imageBase64 === "string" && attachment.imageBase64.trim().length > 0;
  const hasImageRef = typeof attachment.imageRef === "string" && attachment.imageRef.trim().length > 0;
  const hasEvidenceRef = typeof attachment.evidenceRef === "string" && attachment.evidenceRef.trim().length > 0;
  const mimeType = typeof attachment.mimeType === "string" ? attachment.mimeType : "";
  const unsupportedType = mimeType.length > 0 && !mimeType.startsWith("image/");
  const tooLarge = typeof attachment.sizeBytes === "number" && attachment.sizeBytes > 8 * 1024 * 1024;
  const hasPayload = hasImageBase64 || hasImageRef || hasEvidenceRef;
  const status: HelixAttachmentCommitCheck["status"] =
    attachment.status === "error"
      ? "missing_payload"
      : unsupportedType
        ? "unsupported_type"
        : tooLarge
          ? "too_large"
          : hasPayload
            ? "ready"
            : "stale_after_restart";
  const canSubmit = status === "ready";
  return {
    schema: "helix.attachment_commit_check.v1",
    attachment_id: attachment.id,
    file_name: attachment.fileName,
    mime_type: attachment.mimeType,
    status,
    can_submit: canSubmit,
    turn_input_item_preview: hasPayload
      ? {
          type: hasEvidenceRef && !hasImageBase64 && !hasImageRef ? "evidence_ref" : "image",
          has_image_base64: hasImageBase64,
          has_image_ref: hasImageRef,
          has_evidence_ref: hasEvidenceRef,
          raw_image_scope: hasImageBase64 ? "turn_input_only" : null,
        }
      : null,
    reason: canSubmit
      ? null
      : status === "stale_after_restart"
        ? "Image attachment is stale. Reattach the image before sending."
        : attachment.error ?? "Image attachment is not ready to submit.",
    assistant_answer: false,
    raw_content_included: false,
  };
}

function isMultilangConfidenceGateResponse(response: AskLocalResult): boolean {
  const failReason = String(response.fail_reason ?? "").trim();
  const failClass = String(response.fail_class ?? "").trim();
  return Boolean(
    response.ok === false &&
      (
        response.error === "multilang_dispatch_blocked" ||
        response.error === "multilang_confirmation_required" ||
        failClass === "multilang_confidence_gate" ||
        /^HELIX_(?:INTERPRETER|MULTILANG)_/i.test(failReason)
      ),
  );
}

async function askLocalWithMultilangFailOpenFallback(
  prompt: string | undefined,
  options?: AskLocalOptions,
): Promise<AskLocalWithFallbackResult> {
  const response = await askLocal(prompt, options);
  if (!isMultilangConfidenceGateResponse(response)) {
    return { response };
  }
  const retryOptions: AskLocalOptions = {
    ...(options ?? {}),
    multilangConfirm: true,
  };
  const retryResponse = await askLocal(prompt, retryOptions);
  if (!retryResponse.mode) {
    retryResponse.mode = "read";
  }
  return {
    response: retryResponse,
    bypassedMultilangGate: true,
  };
}

export async function askLocalWithPreflightScopeFallback(
  prompt: string | undefined,
  options?: AskLocalOptions,
): Promise<AskLocalWithFallbackResult> {
  try {
    return await askLocalWithMultilangFailOpenFallback(prompt, options);
  } catch (error) {
    if (!options?.mode || !isAgibotPreflightScopeError(error)) {
      throw error;
    }
    const retryOptions: AskLocalOptions = { ...options };
    delete retryOptions.mode;
    delete retryOptions.allowTools;
    delete retryOptions.requiredEvidence;
    delete retryOptions.verify;
    const fallback = await askLocalWithMultilangFailOpenFallback(prompt, retryOptions);
    const response = fallback.response;
    if (!response.mode) {
      response.mode = "read";
    }
    return {
      response,
      downgradedFromMode: options.mode,
      bypassedMultilangGate: fallback.bypassedMultilangGate,
    };
  }
}

export function formatVoiceDecisionSentence(args: {
  lifecycle: VoiceDecisionLifecycle;
  mode?: "observe" | "act" | "verify" | "clarify";
  routeReasonCode?: string | null;
  escalatedMode?: "verify" | "act";
  failureReasonRaw?: string | null;
}): string {
  const reasonCode = normalizeConversationRouteReasonCode(args.routeReasonCode);
  const normalizedFailureReason = normalizeVoiceFailureReasonText(args.failureReasonRaw ?? args.routeReasonCode);
  if (args.lifecycle === "queued") {
    if (reasonCode === "dispatch:verify") return "I am thinking through a verification pass in the background.";
    if (reasonCode === "dispatch:act") return "I am thinking through an action-oriented pass in the background.";
    if (reasonCode === "dispatch:observe_explore") return "I am thinking through this in the background.";
    if (reasonCode === "dispatch:observe") return "I am thinking through this in the background.";
    return "I am thinking through this in the background.";
  }
  if (args.lifecycle === "running") {
    return `Reasoning is running in ${laneLabelForConversationMode(args.mode)} mode.`;
  }
  if (args.lifecycle === "suppressed") {
    if (normalizedFailureReason === "the run was interrupted by a newer turn") {
      return "Switched to your newer request.";
    }
    if (reasonCode === "suppressed:filler") {
      return "Reasoning is suppressed for this filler turn.";
    }
    if (reasonCode === "suppressed:clarify_after_attempt1") {
      return "Reasoning is paused until you share one concrete detail.";
    }
    if (reasonCode === "suppressed:low_salience") {
      return "Reasoning is suppressed for now while we keep this conversational.";
    }
    if (normalizedFailureReason) {
      return `Reasoning is paused because ${normalizedFailureReason}.`;
    }
    return "Reasoning is suppressed for this turn.";
  }
  if (args.lifecycle === "escalated") {
    if (args.escalatedMode === "verify") return "Reasoning is escalated to verification mode.";
    if (args.escalatedMode === "act") return "Reasoning is escalated to action mode.";
    return "Reasoning is escalated to a deeper lane.";
  }
  if (args.lifecycle === "done") {
    if (args.mode === "act") return "Action reasoning is complete; see the receipt below.";
    return "Reasoning is complete; see the answer below.";
  }
  if (normalizedFailureReason === "the run was interrupted by a newer turn") {
    return "Switched to your newer request.";
  }
  if (normalizedFailureReason) {
    return `Reasoning failed for this turn because ${normalizedFailureReason}.`;
  }
  return "Reasoning failed for this turn; I can retry on your next prompt.";
}

export function shouldAutoSpeakVoiceDecisionLifecycle(
  lifecycle: VoiceDecisionLifecycle | undefined,
  options?: {
    routeReasonCode?: string | null;
    failReasonRaw?: string | null;
  },
): boolean {
  if (lifecycle === "queued") return true;
  if (lifecycle === "running") return true;
  if (lifecycle === "suppressed") {
    const reasonCode = normalizeConversationRouteReasonCode(options?.routeReasonCode);
    if (
      reasonCode === "suppressed:clarify_after_attempt1" ||
      reasonCode === "suppressed:clarify_after_artifact_retry_exhausted"
    ) {
      return true;
    }
    return false;
  }
  if (lifecycle === "failed") return false;
  return false;
}

export type VoiceAutoSpeakAnswerToolIntent =
  | "none"
  | "tool_only"
  | "explicit_voice_tool"
  | "workspace_terminal_summary";

export function shouldAutoSpeakAnswerForTurn(args: {
  micArmState: MicArmState;
  inputSource?: ReasoningAttemptSource | null;
  voiceMode?: string | null;
  userMuted?: boolean;
  answerAuthority?: VoicePlaybackIntentAuthority | "sealed_final" | "provisional" | null;
  toolIntent?: VoiceAutoSpeakAnswerToolIntent | null;
  finalTimelineType?: "reasoning_final" | "action_receipt" | "workspace_terminal_summary" | string | null;
}): boolean {
  if (args.micArmState !== "on") return false;
  if (args.userMuted) return false;
  if (args.toolIntent === "tool_only" || args.toolIntent === "explicit_voice_tool") return false;
  if (
    args.finalTimelineType &&
    args.finalTimelineType !== "reasoning_final" &&
    args.finalTimelineType !== "workspace_terminal_summary"
  ) {
    return false;
  }
  if (args.answerAuthority !== "final" && args.answerAuthority !== "sealed_final") return false;
  return args.inputSource === "voice_auto" || args.inputSource === "manual";
}

export function shouldPreserveAuthoritativeTerminalOverEvidenceGate(args: {
  evidenceGateBlocked: boolean;
  dispatchPolicy?: string | null;
  routeReasonCode?: string | null;
  finalAnswerSource?: string | null;
  terminalArtifactKind?: string | null;
  hasCompletedWorkspaceTool?: boolean;
  hasTerminalText?: boolean;
  hasPendingRequest?: boolean;
}): boolean {
  if (!args.evidenceGateBlocked) return false;
  if (!args.hasTerminalText) return false;
  if (
    args.finalAnswerSource &&
    !["unknown", "typed_failure", "legacy_fallback"].includes(args.finalAnswerSource) &&
    args.terminalArtifactKind &&
    !["unknown", "typed_failure"].includes(args.terminalArtifactKind)
  ) {
    return true;
  }
  if (args.finalAnswerSource === "artifact_synthesis" && args.terminalArtifactKind === "situation_context_pack") {
    return true;
  }
  if (args.finalAnswerSource === "artifact_synthesis" && args.routeReasonCode === "situation_context_pack") {
    return true;
  }
  if (args.finalAnswerSource === "artifact_synthesis" && args.terminalArtifactKind === "doc_summary") {
    return true;
  }
  if (args.finalAnswerSource === "artifact_synthesis" && args.routeReasonCode?.includes("active_doc_summary")) {
    return true;
  }
  if (args.finalAnswerSource === "workstation_reasoning_trace" && args.routeReasonCode === "proof_recall") {
    return true;
  }
  if (args.finalAnswerSource === "workstation_tool_evaluation" && args.terminalArtifactKind === "workstation_tool_evaluation") {
    return true;
  }
  if (args.hasPendingRequest) return true;
  if (
    (args.dispatchPolicy === "workspace_only" || args.dispatchPolicy === "workspace_context_reasoning") &&
    args.routeReasonCode === "dispatch:act" &&
    args.hasCompletedWorkspaceTool
  ) {
    return true;
  }
  return args.dispatchPolicy === "direct_answer_only" && args.routeReasonCode === "conversation:simple";
}

export function shouldSuppressVoiceForTerminalState(args: {
  dispatchPolicy?: string | null;
  routeReasonCode?: string | null;
  terminalKind?: string | null;
  finalAnswerSource?: string | null;
  hasPendingRequest?: boolean;
}): boolean {
  if (args.hasPendingRequest) return true;
  if (args.dispatchPolicy === "needs_user_input") return true;
  if (args.routeReasonCode?.startsWith("clarify:")) return true;
  if (args.terminalKind === "final_failure" || args.terminalKind === "typed_failure") return true;
  if (args.finalAnswerSource === "typed_failure") return true;
  return false;
}

export function isGenericQueuedVoiceAcknowledgement(text: string): boolean {
  const normalized = text.trim().toLowerCase();
  if (!normalized) return false;
  return (
    normalized === "got it. i am thinking through this in the background." ||
    normalized === "got it. thinking in the background." ||
    normalized === "i am thinking through this in the background." ||
    normalized === "reasoning is running in the background." ||
    /^reasoning is running in [a-z ]+ mode\.$/.test(normalized) ||
    normalized ===
      "got it. i will run a short observe reasoning pass in the background so we can keep talking while it loads."
  );
}

function isGenericRunningVoiceStatus(text: string): boolean {
  const normalized = text.trim().toLowerCase();
  if (!normalized) return false;
  if (normalized === "reasoning is running in the background.") return true;
  return /^reasoning is running in [a-z ]+ mode\.$/.test(normalized);
}

function isPinnedVoiceBriefCandidate(text: string): boolean {
  const normalized = sanitizeConversationBriefTextForVoice(text, 560);
  if (!normalized) return false;
  if (isGenericQueuedVoiceAcknowledgement(normalized)) return false;
  if (/^i heard:\s*"/i.test(normalized)) return false;
  return normalized.split(/\s+/).filter(Boolean).length >= 9;
}

export function shouldInterruptForSupersededReason(
  reason: VoicePlaybackCancelReason | null,
  hasActiveAudio: boolean,
): boolean {
  if (!reason) return false;
  if (reason === "superseded_same_turn") {
    // Prefer boundary handoff for same-turn brief/final refreshes to avoid audible hard cuts.
    return false;
  }
  if (reason === "preempted_by_final" && !hasActiveAudio) {
    return false;
  }
  return true;
}

export function isRetryableVoiceChunkSynthesisError(error: unknown): boolean {
  const err = error as {
    status?: unknown;
    name?: unknown;
    message?: unknown;
  } | null;
  const status = typeof err?.status === "number" && Number.isFinite(err.status) ? err.status : null;
  const name = typeof err?.name === "string" ? err.name.toLowerCase() : "";
  const message =
    error instanceof Error
      ? error.message.toLowerCase()
      : typeof err?.message === "string"
        ? err.message.toLowerCase()
        : String(error ?? "").toLowerCase();
  if (message.startsWith("voice_auto_speak_suppressed:")) return false;
  if (name === "aborterror" || /\babort(ed)?\b/.test(message)) return false;
  if (status !== null && (status === 408 || status === 425 || status === 429 || status >= 500)) {
    return true;
  }
  return /\b(failed to fetch|networkerror|network request failed|load failed|fetch failed|timeout|timed out|temporarily unavailable)\b/.test(
    message,
  );
}

function mapVoicePreemptPolicyToCancelReason(
  policy: Exclude<VoicePreemptPolicy, "none">,
): VoicePlaybackCancelReason {
  return policy === "pending_final" ? "preempted_by_final" : "superseded_same_turn";
}

export function composeVoiceBriefWithDecision(baseBrief: string, decisionSentence: string): string {
  const brief = baseBrief.trim();
  const decision = decisionSentence.trim();
  if (!brief) return clipText(decision, 640);
  if (!decision) return clipText(brief, 640);
  const separator = /[.!?]["')\]]?$/.test(brief) ? " " : ". ";
  return clipText(`${brief}${separator}${decision}`, 640);
}

function normalizeConversationBriefSource(value: unknown): "llm" | "none" {
  return value === "llm" ? "llm" : "none";
}

function buildSuppressedVoiceSpeechText(args: {
  entryText: string;
  decisionSentence: string;
  routeReasonCode?: string | null;
  failReasonRaw?: string | null;
}): string {
  const combinedReason = `${args.routeReasonCode ?? ""} ${args.failReasonRaw ?? ""}`.trim();
  if (isVoiceTurnSupersededReason(combinedReason)) {
    return sanitizeConversationBriefTextForVoice(args.decisionSentence || "Switched to your newer request.", 240);
  }
  const normalized = sanitizeConversationBriefTextForVoice(args.entryText, 560);
  if (!normalized) {
    return "";
  }
  const reasonCode = normalizeConversationRouteReasonCode(args.routeReasonCode);
  const sentenceBudget = reasonCode === "suppressed:filler" || reasonCode === "suppressed:low_salience" ? 2 : 1;
  const sentences = normalized
    .split(/(?<=[.!])\s+/)
    .map((entry) => entry.trim())
    .filter(Boolean);
  const selected = sentences.slice(0, sentenceBudget);
  const selectedLower = selected.map((entry) => entry.toLowerCase());
  const decision = sanitizeConversationBriefTextForVoice(args.decisionSentence, 220);
  if (decision && !selectedLower.includes(decision.toLowerCase())) {
    selected.push(decision);
  }
  return clipText(sanitizeConversationBriefTextForVoice(selected.join(" "), 360), 360);
}

export function buildVoiceInputStatusLabel(
  micArmState: MicArmState,
  state: MicRuntimeState,
  error: string | null,
): string | null {
  if (micArmState === "off") return null;
  if (state === "listening") return "Listening";
  if (state === "transcribing") return "Transcribing";
  if (state === "cooldown") return "Cooldown";
  if (state === "error") return error ?? "Voice input unavailable.";
  return null;
}

function describeVoiceInputError(error: unknown): string {
  if (error instanceof Error) {
    const msg = error.message.trim();
    if (/STT HTTP 401/i.test(msg)) {
      return "OpenAI STT unauthorized (401). Check OPENAI_API_KEY on server :5050.";
    }
    if (/STT HTTP 403/i.test(msg)) {
      return "OpenAI STT forbidden (403). Check key permissions and organization/project access.";
    }
    if (/STT HTTP 429/i.test(msg)) {
      return "OpenAI STT rate-limited (429). Retry shortly or adjust limits.";
    }
    if (/HULL|not allowed|ENOTFOUND|EAI_AGAIN|ECONN|network|fetch/i.test(msg)) {
      return "STT network/allowlist failure. Verify outbound host allowlist includes api.openai.com.";
    }
    if (error.name === "NotAllowedError" || error.name === "PermissionDeniedError") {
      return "Microphone permission denied.";
    }
    if (error.name === "NotFoundError" || error.name === "DevicesNotFoundError") {
      return "No microphone available.";
    }
    if (error.name === "NotReadableError" || error.name === "TrackStartError") {
      return "Microphone is busy.";
    }
    if (msg) {
      return msg;
    }
  }
  return "Voice input unavailable.";
}

function isVoiceMemoryPressureError(error: unknown): boolean {
  if (!(error instanceof Error)) return false;
  const status = (error as { status?: unknown }).status;
  return (
    status === 503 &&
    /voice_memory_pressure|memory pressure|temporarily paused/i.test(error.message)
  );
}

