function readNumber(value: unknown, fallback: number): number {
  const parsed = Number(value);
  return Number.isFinite(parsed) ? parsed : fallback;
}

function clampNumber(value: number, min: number, max: number): number {
  return Math.min(max, Math.max(min, value));
}

function clipText(value: string | undefined, limit: number): string {
  if (!value) return "";
  if (value.length <= limit) return value;
  return `${value.slice(0, limit)}...`;
}

function coerceText(value: unknown): string {
  if (value === null || value === undefined) return "";
  if (typeof value === "string") return value;
  try {
    return String(value);
  } catch {
    return "";
  }
}

function parseChatMessageTimeMs(message: ChatMessage): number | null {
  const parsed = Date.parse(message.at);
  return Number.isFinite(parsed) ? parsed : null;
}

function buildHelixAskChatProjectionId(
  session: ChatSession,
  userMessage: ChatMessage | null,
  assistantMessage: ChatMessage,
): string {
  const traceId = assistantMessage.traceId?.trim() || userMessage?.traceId?.trim();
  if (traceId) return `helix-chat-turn:${session.id}:${traceId}`;
  return `helix-chat-turn:${session.id}:${userMessage?.id ?? "standalone"}:${assistantMessage.id}`;
}

const STAGE_PLAY_MAIL_WAKE_PROMPT_PATTERNS = [
  /\bstage_play_live_source_mail_wake:/i,
  /^\s*use\s+live_env\.(?:read_live_source_mail|read_processed_live_source_mail|record_live_source_mail_decision|request_interim_voice_callout)\b/i,
  /^\s*read the active stage play live-source mailbox and use the latest processed micro-reasoner finding\b/i,
  /^\s*review the latest stage play live-source mailbox finding\.\s*use the structured mailbox route metadata attached to this turn\b/i,
  /^\s*review the latest stage play live-source mailbox finding\.[\s\S]*?\bmicro-reasoner recommendation:\s*(?:record\s+interpretation|request\s+voice\s+callout|request\s+more\s+evidence|request\s+stage\s+play\s+checkpoint|draft\s+text\s+answer)\b[\s\S]*?\bstructured mailbox route metadata attached\b/i,
  /^\s*review the latest stage play live-source mailbox finding\.[\s\S]*?\bmicro-reasoner recommendation:\s*request\s+voice\s+callout\b[\s\S]*?\bstructured mailbox route metadata attached\b/i,
  /\bui bridge reason:\s*(?:backend wake admission deferred|micro-reasoner wake candidate|operator opened queued wake)/i,
];

const STAGE_PLAY_MAIL_WAKE_ASSISTANT_PATTERNS = [
  /\bi could not complete this live-source turn\b/i,
  /\bthe live-source mailbox route completed\b/i,
  /\bthe interim voice callout\b/i,
  /\bsolver authority failed\b/i,
  /\bselected:\s*live_env\./i,
  /\bphase:\s*(?:terminal_checkpoint|record_decision|request_voice_after_decision)\b/i,
  /\bvoice callout request\b/i,
];

function isGeneratedStagePlayMailWakePrompt(message: ChatMessage | null): boolean {
  if (!message || message.role !== "user") return false;
  const text = message.content.trim();
  if (!text) return false;
  return STAGE_PLAY_MAIL_WAKE_PROMPT_PATTERNS.some((pattern) => pattern.test(text));
}

function isGeneratedStagePlayMailWakeAssistantProjection(message: ChatMessage | null): boolean {
  if (!message || message.role !== "assistant") return false;
  const text = message.content.trim();
  if (!text) return false;
  return STAGE_PLAY_MAIL_WAKE_ASSISTANT_PATTERNS.some((pattern) => pattern.test(text));
}

function shouldSuppressGeneratedStagePlayMailWakeChatProjection(
  userMessage: ChatMessage | null,
  assistantMessage: ChatMessage,
): boolean {
  if (!isGeneratedStagePlayMailWakePrompt(userMessage)) return false;
  if (isGeneratedStagePlayMailWakeAssistantProjection(assistantMessage)) return true;
  return false;
}

export function buildHelixAskRepliesFromChatSession(session: ChatSession): HelixAskReply[] {
  const messages = [...(session.messages ?? [])].sort((left, right) => {
    const leftMs = parseChatMessageTimeMs(left);
    const rightMs = parseChatMessageTimeMs(right);
    if (leftMs !== null && rightMs !== null && leftMs !== rightMs) return leftMs - rightMs;
    if (leftMs !== null && rightMs === null) return -1;
    if (leftMs === null && rightMs !== null) return 1;
    return left.id.localeCompare(right.id);
  });
  const replies: HelixAskReply[] = [];
  let pendingUser: ChatMessage | null = null;
  for (const message of messages) {
    if (message.role === "user") {
      pendingUser = message;
      continue;
    }
    if (message.role !== "assistant") continue;
    const answer = message.content.trim();
    if (!answer) continue;
    if (isHelixAskProgressPlaceholderText(answer)) {
      pendingUser = null;
      continue;
    }
    if (shouldSuppressGeneratedStagePlayMailWakeChatProjection(pendingUser, message)) {
      pendingUser = null;
      continue;
    }
    const createdAtMs = parseChatMessageTimeMs(message) ?? parseChatMessageTimeMs(pendingUser ?? message) ?? Date.now();
    const turnId = message.traceId?.trim() || pendingUser?.traceId?.trim() || null;
    replies.push({
      id: buildHelixAskChatProjectionId(session, pendingUser, message),
      createdAtMs,
      content: answer,
      question: pendingUser?.content ?? "",
      turn_id: turnId,
      ok: true,
      final_answer_source: "durable_chat_session",
      terminal_artifact_kind: "chat_final_answer",
      debug: {
        durable_chat_projection: true,
        session_id: session.id,
        user_message_id: pendingUser?.id ?? null,
        assistant_message_id: message.id,
        created_at_ms: createdAtMs,
        turn_id: turnId,
      } as HelixAskReply["debug"],
    });
    pendingUser = null;
  }
  return replies;
}

function readAgentLoopAuditRecord(value: unknown): Record<string, unknown> | null {
  return value && typeof value === "object" && !Array.isArray(value) ? (value as Record<string, unknown>) : null;
}

function extractAskLevelTheoryReflection(value: unknown): TheoryContextReflectionV1 | null {
  const record = readAgentLoopAuditRecord(value);
  if (!record) return null;
  const directReceipt = readAgentLoopAuditRecord(record.theory_context_reflection_tool_receipt);
  if (isTheoryContextReflectionV1(directReceipt?.reflectionV1)) return directReceipt.reflectionV1;
  const directArtifact = readAgentLoopAuditRecord(record.artifact_v1);
  if (isTheoryContextReflectionV1(directArtifact?.reflectionV1)) return directArtifact.reflectionV1;
  const ledger = Array.isArray(record.current_turn_artifact_ledger) ? record.current_turn_artifact_ledger : [];
  for (const item of ledger) {
    const artifact = readAgentLoopAuditRecord(item);
    if (!artifact || artifact.kind !== "helix_theory_context_reflection_tool_receipt") continue;
    const payload = readAgentLoopAuditRecord(artifact.payload);
    const artifactV1 = readAgentLoopAuditRecord(payload?.artifact_v1);
    if (isTheoryContextReflectionV1(artifactV1?.reflectionV1)) return artifactV1.reflectionV1;
    if (isTheoryContextReflectionV1(payload?.reflectionV1)) return payload.reflectionV1;
  }
  return null;
}

type HelixActionEnvelopeRuntimeAuthority = {
  schema: "helix.ui.action_envelope_runtime_authority.v1";
  allowed: boolean;
  reason: string;
  selected_capabilities: string[];
  envelope_action_keys: string[];
  assistant_answer: false;
  raw_content_included: false;
};

function normalizeHelixRuntimeActionKey(value: unknown): string {
  return coerceText(value).trim().toLowerCase().replace(/[/:]+/g, ".").replace(/\s+/g, "_");
}

function readHelixDecisionCapabilityKeys(value: unknown): string[] {
  const record = readAgentLoopAuditRecord(value);
  if (!record) return [];
  const directKeys = [
    record.chosen_capability,
    record.selected_capability,
    record.capability_key,
    record.executed_action_key,
    record.action_key,
    record.tool_key,
    record.tool_name,
  ]
    .map(normalizeHelixRuntimeActionKey)
    .filter(Boolean);
  const nestedKeys = [
    record.agent_step_decision,
    record.initial_agent_step_decision,
    record.tool_call,
    record.next_action,
    record.selected_action,
    record.action,
  ].flatMap(readHelixDecisionCapabilityKeys);
  return [...directKeys, ...nestedKeys];
}

function collectHelixAgentSelectedCapabilities(...sources: unknown[]): string[] {
  const selected = new Set<string>();
  const add = (value: unknown): void => {
    readHelixDecisionCapabilityKeys(value).forEach((key) => selected.add(key));
  };
  sources.forEach((source) => {
    const record = readAgentLoopAuditRecord(source);
    if (!record) return;
    const debug = readAgentLoopAuditRecord(record.debug);
    [
      record.agent_step_decision,
      record.initial_agent_step_decision,
      record.observation_review,
      record.runtime_authority_audit,
      debug?.agent_step_decision,
      debug?.initial_agent_step_decision,
      debug?.observation_review,
      debug?.runtime_authority_audit,
    ].forEach(add);
    [record.agent_runtime_loop, debug?.agent_runtime_loop, record.agent_step_loop, debug?.agent_step_loop].forEach((loop) => {
      const loopRecord = readAgentLoopAuditRecord(loop);
      const iterations = Array.isArray(loopRecord?.iterations)
        ? loopRecord?.iterations
        : Array.isArray(loopRecord?.steps)
          ? loopRecord?.steps
          : [];
      iterations.forEach(add);
    });
  });
  return [...selected].filter(Boolean);
}

function readLatestHelixRuntimeChosenCapability(...sources: unknown[]): string | null {
  for (const source of sources) {
    const record = readAgentLoopAuditRecord(source);
    if (!record) continue;
    const debug = readAgentLoopAuditRecord(record.debug);
    const loops = [record.agent_runtime_loop, debug?.agent_runtime_loop, record.agent_step_loop, debug?.agent_step_loop];
    for (const loop of loops) {
      const loopRecord = readAgentLoopAuditRecord(loop);
      const iterations = Array.isArray(loopRecord?.iterations)
        ? loopRecord.iterations
        : Array.isArray(loopRecord?.steps)
          ? loopRecord.steps
          : [];
      for (const iteration of [...iterations].reverse()) {
        const iterationRecord = readAgentLoopAuditRecord(iteration);
        const chosen = coerceText(iterationRecord?.chosen_capability).trim();
        if (chosen) return chosen;
      }
    }
    const direct = coerceText(
      readAgentLoopAuditRecord(record.agent_step_decision)?.chosen_capability ??
        readAgentLoopAuditRecord(debug?.agent_step_decision)?.chosen_capability ??
        record.chosen_capability,
    ).trim();
    if (direct) return direct;
  }
  return null;
}

function readHelixWorkstationActionRuntimeKeys(action: HelixWorkstationAction | Record<string, unknown>): string[] {
  const record = readAgentLoopAuditRecord(action);
  if (!record) return [];
  const panelId = normalizeHelixRuntimeActionKey(record.panel_id);
  const actionId = normalizeHelixRuntimeActionKey(record.action_id);
  const actionName = normalizeHelixRuntimeActionKey(record.action);
  const keys = new Set<string>();
  if (panelId && actionId) {
    keys.add(`${panelId}.${actionId}`);
    keys.add(`${panelId}/${actionId}`);
  }
  if (panelId && actionName === "open_panel") keys.add(`${panelId}.open`);
  if (actionName === "restore_view_state") {
    keys.add("workstation.restore_view_state");
    keys.add("workstation/restore_view_state");
  }
  if (panelId && actionName) keys.add(`${panelId}.${actionName}`);
  if (actionId) keys.add(actionId);
  if (actionName) keys.add(actionName);
  return [...keys].map(normalizeHelixRuntimeActionKey).filter(Boolean);
}

function buildHelixActionEnvelopeRuntimeAuthority(
  envelope: HelixActionEnvelope | undefined,
  ...authoritySources: unknown[]
): { executableEnvelope: HelixActionEnvelope | undefined; audit: HelixActionEnvelopeRuntimeAuthority } {
  const dispatch = envelope?.governance?.dispatch ?? "allow";
  if (!envelope || envelope.schema !== "helix.ask.action_envelope.v1") {
    return {
      executableEnvelope: undefined,
      audit: {
        schema: "helix.ui.action_envelope_runtime_authority.v1",
        allowed: false,
        reason: "missing_action_envelope",
        selected_capabilities: [],
        envelope_action_keys: [],
        assistant_answer: false,
        raw_content_included: false,
      },
    };
  }
  const actions = coerceHelixWorkstationActions(envelope.workstation_actions ?? []);
  const envelopeActionKeys: string[] = Array.from(
    new Set<string>(
      actions
        .flatMap(readHelixWorkstationActionRuntimeKeys)
        .map(normalizeHelixRuntimeActionKey)
        .filter((key): key is string => Boolean(key)),
    ),
  );
  const selectedCapabilities = collectHelixAgentSelectedCapabilities(...authoritySources);
  const hasExecutablePayload = envelopeActionKeys.length > 0 || Boolean(envelope.viewer_launch);
  const selectedActionMatched =
    envelopeActionKeys.length === 0
      ? !hasExecutablePayload
      : envelopeActionKeys.some((key) => selectedCapabilities.includes(key));
  const allowed = dispatch === "suppress" || selectedActionMatched;
  return {
    executableEnvelope: allowed ? envelope : undefined,
    audit: {
      schema: "helix.ui.action_envelope_runtime_authority.v1",
      allowed,
      reason:
        dispatch === "suppress"
          ? "server_suppressed_dispatch"
          : selectedActionMatched
            ? "agent_step_decision_backed"
            : "agent_step_decision_missing_for_action_envelope",
      selected_capabilities: selectedCapabilities,
      envelope_action_keys: envelopeActionKeys,
      assistant_answer: false,
      raw_content_included: false,
    },
  };
}

function attachHelixActionEnvelopeRuntimeAuthorityDebug<T extends Record<string, unknown> | undefined>(
  debug: T,
  envelope: HelixActionEnvelope | undefined,
  authority: HelixActionEnvelopeRuntimeAuthority,
): T {
  if (!debug) return debug;
  return {
    ...debug,
    action_envelope_runtime_authority: authority,
    action_envelope: authority.allowed /* runtime_authority */ ? envelope ?? null : null,
    suppressed_action_envelope: authority.allowed ? null : envelope ?? null,
  } as T;
}

function readHelixPendingInputRecord(value: unknown): Record<string, unknown> | null {
  const record = readAgentLoopAuditRecord(value);
  if (!record) return null;
  const status = coerceText(record.status ?? record.state ?? record.resolution_status).trim().toLowerCase();
  if (status === "resolved" || status === "cancelled" || status === "canceled" || status === "superseded") {
    return null;
  }
  const requestId = coerceText(record.request_id ?? record.requestId ?? record.id).trim();
  const prompt = coerceText(record.prompt ?? record.message ?? record.text ?? record.question).trim();
  const requiredFieldsCandidate = record.required_fields ?? record.requiredFields;
  const requiredFields = Array.isArray(requiredFieldsCandidate) ? requiredFieldsCandidate : [];
  if (requestId || prompt || requiredFields.length > 0 || record.kind === "request_user_input") return record;
  return null;
}

function normalizeHelixPendingTransitionMarker(value: unknown): string {
  return coerceText(value).trim().toLowerCase().replace(/[\s-]+/g, "_");
}

function readHelixPendingTransitionTrace(value: unknown): string[] {
  if (Array.isArray(value)) {
    return value.map((entry) => normalizeHelixPendingTransitionMarker(entry)).filter(Boolean);
  }
  const text = normalizeHelixPendingTransitionMarker(value);
  return text ? [text] : [];
}

function hasHelixPendingCancellationMarker(record: Record<string, unknown>): boolean {
  const pendingStatusAfter = normalizeHelixPendingTransitionMarker(
    record.pending_status_after ?? record.pendingStatusAfter ?? record.status_after,
  );
  if (pendingStatusAfter === "canceled" || pendingStatusAfter === "cancelled") return true;

  const pendingContext =
    record.pending_intercepted_turn === true ||
    Boolean(record.pending_status_before ?? record.pending_status_after) ||
    Boolean(record.pending_request ?? record.pending_server_request ?? record.pendingRequest) ||
    readHelixPendingTransitionTrace(record.pending_transition_trace).length > 0;
  if (!pendingContext) return false;

  const markers = [
    record.pending_transition_reason,
    record.pendingTransitionReason,
    record.pending_interception_reason,
    record.pendingInterceptionReason,
    record.pending_resolution_reason,
    record.pendingResolutionReason,
    record.resolution_reason,
    record.reason,
    ...readHelixPendingTransitionTrace(record.pending_transition_trace),
  ].map((entry) => normalizeHelixPendingTransitionMarker(entry));
  return markers.some(
    (marker) =>
      marker === "pending_clarify_canceled" ||
      marker === "pending_request_canceled" ||
      marker === "request_user_input_canceled" ||
      marker === "cancel_pending" ||
      marker === "canceled_pending_request" ||
      marker.includes("pending_clarify_canceled"),
  );
}

function isHelixCanceledPendingTurn(...sources: unknown[]): boolean {
  const stack = sources
    .map((source) => readAgentLoopAuditRecord(source))
    .filter((record): record is Record<string, unknown> => Boolean(record));
  const seen = new WeakSet<object>();
  while (stack.length > 0) {
    const record = stack.pop();
    if (!record || seen.has(record)) continue;
    seen.add(record);
    if (hasHelixPendingCancellationMarker(record)) return true;
    [
      record.debug,
      record.agent_loop_audit,
      record.turn_truth_table,
      record.turn_runtime,
      record.runtime_summary,
      record.terminal,
    ].forEach((candidate) => {
      const nested = readAgentLoopAuditRecord(candidate);
      if (nested && !seen.has(nested)) stack.push(nested);
    });
  }
  return false;
}

function resolveHelixPendingInputRecord(...sources: unknown[]): Record<string, unknown> | null {
  if (isHelixCanceledPendingTurn(...sources)) return null;
  for (const source of sources) {
    const record = readAgentLoopAuditRecord(source);
    if (!record) continue;
    const direct = readHelixPendingInputRecord(record);
    if (direct && (record.prompt || record.request_id || record.requestId || record.required_fields || record.requiredFields)) {
      return direct;
    }
    const agentLoopAudit = readAgentLoopAuditRecord(record.agent_loop_audit);
    const turnTruthTable = readAgentLoopAuditRecord(record.turn_truth_table);
    const runtimeSummary = readAgentLoopAuditRecord(record.turn_runtime ?? agentLoopAudit?.runtime_summary);
    const pendingCandidates = [
      record.pending_request,
      record.pending_server_request,
      record.pendingRequest,
      record.server_request,
      record.request_user_input,
      agentLoopAudit?.pending_request,
      agentLoopAudit?.pending_server_request,
      turnTruthTable?.pending_request,
      turnTruthTable?.pending_transition,
      runtimeSummary?.pending_request,
    ];
    for (const candidate of pendingCandidates) {
      const pending = readHelixPendingInputRecord(candidate);
      if (pending) return pending;
    }
  }
  return null;
}

function resolveHelixVisibleTerminalKind(args: {
  reply?: HelixAskReply | null;
  terminal?: Record<string, unknown> | null;
  fallback?: string;
  extraSources?: unknown[];
}): string {
  if (isHelixCanceledPendingTurn(args.reply, args.reply?.debug, args.terminal, ...(args.extraSources ?? []))) {
    return "canceled";
  }
  if (args.reply) {
    return buildVisibleResolvedTurn(args.reply).primary_terminal_label;
  }
  const terminalKind = typeof args.terminal?.kind === "string" ? args.terminal.kind : null;
  if (terminalKind === "final_answer" || terminalKind === "final_failure") {
    return terminalKind;
  }
  const pending = resolveHelixPendingInputRecord(args.reply, args.reply?.debug, ...(args.extraSources ?? []));
  if (pending) return "pending_input";
  return String(terminalKind ?? args.fallback ?? "n/a");
}

function resolveHelixTranscriptActionLabel(event: Record<string, unknown>): string | null {
  const directPanelId = coerceText(event.panel_id ?? event.panelId).trim();
  const directActionId = coerceText(event.action_id ?? event.actionId).trim();
  if (directPanelId && directActionId) return `${directPanelId}.${directActionId}`;

  const action =
    readAgentLoopAuditRecord(event.action) ??
    readAgentLoopAuditRecord(event.selected_action) ??
    readAgentLoopAuditRecord(event.tool_action);
  const panelId = coerceText(action?.panel_id ?? action?.panelId).trim();
  const actionId = coerceText(action?.action_id ?? action?.actionId).trim();
  if (panelId && actionId) return `${panelId}.${actionId}`;

  const stepId = coerceText(event.step_id ?? event.stepId).trim();
  if (/^workspace_action_locate_(?:exact|variant|doc)$/i.test(stepId)) {
    return "docs-viewer.locate_in_doc";
  }
  if (/^workspace_action_append_(?:location_reminder|to_note|doc_summary)$/i.test(stepId)) {
    return "workstation-notes.append_to_note";
  }
  if (/^workspace_action_docs_viewer_summarize_doc$/i.test(stepId)) {
    return "docs-viewer.summarize_doc";
  }
  if (/^workspace_action_docs_viewer_search_docs$/i.test(stepId)) {
    return "docs-viewer.search_docs";
  }

  const toolName = coerceText(event.tool ?? event.tool_name ?? event.capability).trim();
  return toolName || null;
}

function normalizeHelixVisibleEventText(value: unknown): string {
  return coerceText(value).replace(/\s+/g, " ").trim().toLowerCase();
}

function buildHelixVisibleActionReceiptKey(event: Record<string, unknown>): string | null {
  const type = String(event.type ?? event.kind ?? "");
  if (type !== "action_receipt" && type !== "workstation_action_receipt" && type !== "tool_result") return null;
  const text = normalizeHelixVisibleEventText(event.text);
  if (!text) return null;
  const turnKey = coerceText(event.turnKey ?? event.turn_key ?? event.traceId ?? event.trace_id);
  const status = coerceText(event.status);
  const stepId = coerceText(event.step_id ?? event.stepId);
  return [turnKey, type, status, stepId, text].filter(Boolean).join("|");
}

function dedupeHelixVisibleTranscriptEvents(events: Record<string, unknown>[]): Record<string, unknown>[] {
  const seen = new Set<string>();
  const out: Record<string, unknown>[] = [];
  for (const event of events) {
    const key = buildHelixVisibleActionReceiptKey(event);
    if (key) {
      if (seen.has(key)) continue;
      seen.add(key);
    }
    out.push(event);
  }
  return out;
}

type HelixAskVisibleTerminalResolution = {
  text: string;
  source: string;
  backendTerminalText: string | null;
};

type VisibleResolvedTurn = {
  active_turn_id: string;
  primary_route_label: string;
  primary_terminal_label: "final_answer" | "final_failure" | "pending_input";
  primary_source_label: string;
  selected_final_answer: string;
  terminal_error_code?: string | null;
  pending_server_request_present: boolean;
};

function readHelixAskTerminalText(record: Record<string, unknown> | null | undefined): string | null {
  if (!record) return null;
  const text = typeof record.text === "string" ? record.text.trim() : "";
  return text.length > 0 ? text : null;
}

const stableHelixProjectionHash = (value: string): string => {
  let hash = 2166136261;
  for (let index = 0; index < value.length; index += 1) {
    hash ^= value.charCodeAt(index);
    hash = Math.imul(hash, 16777619);
  }
  return (hash >>> 0).toString(16).padStart(8, "0");
};

const readHelixResolvedTurnSummary = (reply?: HelixAskReply | null): Record<string, unknown> | null => {
  const record = readAgentLoopAuditRecord(reply);
  const debugRecord = readAgentLoopAuditRecord(reply?.debug);
  const turnTruthTable = readAgentLoopAuditRecord(record?.turn_truth_table ?? debugRecord?.turn_truth_table);
  return readAgentLoopAuditRecord(record?.resolved_turn_summary ?? debugRecord?.resolved_turn_summary ?? turnTruthTable?.resolved_turn_summary);
};

const readHelixCanonicalGoalKind = (reply?: HelixAskReply | null): string => {
  const record = readAgentLoopAuditRecord(reply);
  const debugRecord = readAgentLoopAuditRecord(reply?.debug);
  const canonical = readAgentLoopAuditRecord(record?.canonical_goal_frame ?? debugRecord?.canonical_goal_frame);
  return coerceText(canonical?.goal_kind).trim() || "unknown";
};

const readHelixTopLevelPendingServerRequest = (reply?: HelixAskReply | null): Record<string, unknown> | null => {
  const record = readAgentLoopAuditRecord(reply);
  return readHelixPendingInputRecord(record?.pending_server_request);
};

const readLatestAuthoritativeFinalLiveEventText = (reply?: HelixAskReply | null): string | null => {
  const replyRecord = readAgentLoopAuditRecord(reply);
  const debugRecord = readAgentLoopAuditRecord(reply?.debug);
  const auditRecord = readAgentLoopAuditRecord(debugRecord?.agent_loop_audit);
  const events = [
    ...(Array.isArray(reply?.liveEvents) ? reply.liveEvents : []),
    ...(Array.isArray(replyRecord?.live_events) ? replyRecord.live_events : []),
    ...(Array.isArray(debugRecord?.live_events) ? debugRecord.live_events : []),
    ...(Array.isArray(debugRecord?.turn_transcript_events) ? debugRecord.turn_transcript_events : []),
    ...(Array.isArray(auditRecord?.turn_transcript_events) ? auditRecord.turn_transcript_events : []),
  ];
  for (let index = events.length - 1; index >= 0; index -= 1) {
    const event = readAgentLoopAuditRecord(events[index]);
    if (!event || typeof event !== "object") continue;
    const rawText = coerceText(event.text).trim();
    const tool = coerceText(event.tool).trim().toLowerCase();
    const type = coerceText(event.type).trim().toLowerCase();
    const meta = readAgentLoopAuditRecord(event.meta);
    const stage = coerceText(meta?.stage ?? meta?.event_stage).trim().toLowerCase();
    const status = coerceText(meta?.status ?? meta?.terminal_status).trim().toLowerCase();
    const isFinalEvent =
      tool === "final" ||
      type === "final_answer" ||
      stage === "final_answer" ||
      status === "final_answer" ||
      /\bfinal_answer\b/i.test(coerceText(event.id)) ||
      /^Final:\s*/i.test(rawText);
    if (!isFinalEvent) continue;
    const text = rawText.replace(/^Final:\s*/i, "").trim();
    if (text && !isInvalidTerminalAnswerText(text)) return text;
  }
  return null;
};

const normalizeVisibleDocPath = (value: string): string | null => {
  const path = value.trim().replace(/:(?:L)?\d+(?:-L?\d+)?$/i, "");
  return path.startsWith("/") ? path : null;
};

const renderDocOpenTerminalFromLocationText = (args: {
  text: string;
  goalKind: string;
  terminalKind: string;
}): string | null => {
  if (args.terminalKind !== "doc_open_receipt") return null;
  if (args.goalKind !== "latest_doc_navigation" && args.goalKind !== "doc_open_best") return null;
  if (!/^\s*Locations?:/i.test(args.text)) return null;
  const pathMatch = args.text.match(/\bPath:\s*(\/[^\s]+?\.md)(?::L?\d+(?:-L?\d+)?)?/i);
  const path = pathMatch?.[1] ? normalizeVisibleDocPath(pathMatch[1]) : null;
  if (!path) return null;
  const titleMatch = args.text.match(/^\s*-\s+(.+?),\s+L\d+/m);
  const title = titleMatch?.[1]?.trim() || path.split(/[\\/]/).pop() || path;
  const heading = args.goalKind === "latest_doc_navigation" ? "Opened latest verified document:" : "Opened document:";
  return [heading, "Document:", `- ${title}`, `  Path: ${path}`].join("\n");
};

const renderLiveAnswerEnvironmentContextPackAnswer = (contextPack: unknown): string | null => {
  const pack = readAgentLoopAuditRecord(contextPack);
  const environment = readAgentLoopAuditRecord(pack?.live_answer_environment);
  if (!environment) return null;
  const summary = coerceText(environment.latest_summary).trim();
  const utilityHypotheses = Array.isArray(pack?.utility_hypotheses) ? pack.utility_hypotheses : [];
  const utilityLines = utilityHypotheses
    .map((entry) => readAgentLoopAuditRecord(entry))
    .slice(-3)
    .map((hypothesis) => {
      const utilityLabel = coerceText(hypothesis?.utility_label).trim();
      if (!utilityLabel) return "";
      const status = coerceText(hypothesis?.status).trim() || "unknown";
      const confidence = typeof hypothesis?.confidence === "number" && Number.isFinite(hypothesis.confidence)
        ? `confidence ${hypothesis.confidence.toFixed(2)}`
        : "confidence unknown";
      const displayLabel = utilityLabel.replace(new RegExp(`^${status}\\s+`, "i"), "");
      return `Hypothesis: ${status} ${displayLabel} (${confidence}).`;
    })
    .filter(Boolean);
  const missingEvidence = Array.isArray(pack?.missing_evidence_notes)
    ? pack.missing_evidence_notes.map((entry) => coerceText(entry).trim()).filter(Boolean).slice(0, 6)
    : [];
  const missingEvidenceLines = missingEvidence.length > 0
    ? [`Missing evidence: ${missingEvidence.join("; ")}.`]
    : [];
  const semanticConfidence = Array.isArray(pack?.semantic_confidence_ladder)
    ? pack.semantic_confidence_ladder.map((entry) => coerceText(entry).trim()).filter(Boolean).slice(-3)
    : [];
  const semanticLines = semanticConfidence.length > 0
    ? [`Semantic confidence: ${semanticConfidence.join("; ")}.`]
    : [];
  const lines = Array.isArray(environment.lines) ? environment.lines : [];
  const renderedLines = lines
    .map((line) => readAgentLoopAuditRecord(line))
    .filter((line): line is Record<string, unknown> => Boolean(line && line.visibility === "answer_card"))
    .map((line) => {
      const label = coerceText(line.label).trim() || coerceText(line.key).trim() || "Line";
      const value = coerceText(line.value).trim();
      return value ? `${label}: ${value}` : "";
    })
    .filter(Boolean);
  const text = [summary, ...utilityLines, ...missingEvidenceLines, ...semanticLines, ...renderedLines].filter(Boolean).join("\n").trim();
  return text || null;
};

export function buildVisibleResolvedTurn(reply: HelixAskReply): VisibleResolvedTurn {
  const replyRecord = readAgentLoopAuditRecord(reply);
  const debugRecord = readAgentLoopAuditRecord(reply.debug);
  const terminalAuthorityRecord =
    readAgentLoopAuditRecord(replyRecord?.terminal_answer_authority) ??
    readAgentLoopAuditRecord(debugRecord?.terminal_answer_authority);
  const terminalAuthorityTrusted =
    terminalAuthorityRecord?.schema === "helix.turn_terminal_authority.v1" &&
    terminalAuthorityRecord.server_authoritative === true;
  const summary = readHelixResolvedTurnSummary(reply);
  const pendingRequest = readHelixTopLevelPendingServerRequest(reply);
  const pendingPresent = Boolean(pendingRequest);
  const statusCandidate =
    coerceText(summary?.final_status).trim() ||
    coerceText(readAgentLoopAuditRecord(replyRecord?.satisfaction_report ?? debugRecord?.satisfaction_report)?.terminal_kind).trim() ||
    (pendingPresent ? "pending_input" : reply.ok === false ? "final_failure" : "final_answer");
  const normalizedStatus: VisibleResolvedTurn["primary_terminal_label"] =
    statusCandidate === "pending_input" && pendingPresent
      ? "pending_input"
      : statusCandidate === "final_failure" || (statusCandidate === "pending_input" && !pendingPresent)
        ? "final_failure"
        : "final_answer";
  const terminalErrorCode =
    coerceText(replyRecord?.terminal_error_code).trim() ||
    coerceText(debugRecord?.terminal_error_code).trim() ||
    coerceText(summary?.terminal_error_code).trim() ||
    (
      !pendingPresent &&
      reply.ok !== false &&
      !terminalAuthorityTrusted &&
      (
        coerceText(replyRecord?.selected_final_answer).trim() ||
        coerceText(debugRecord?.selected_final_answer).trim() ||
        coerceText(reply.assistant_answer).trim() ||
        coerceText(reply.text).trim() ||
        coerceText(reply.content).trim()
      )
        ? "terminal_authority_missing"
        : null
    );
  const finalAnswerSource =
    coerceText(replyRecord?.final_answer_source).trim() ||
    coerceText(debugRecord?.final_answer_source).trim() ||
    coerceText(terminalAuthorityRecord?.final_answer_source).trim() ||
    (terminalErrorCode ? "typed_failure" : "unknown");
  const isTypedFailure = finalAnswerSource === "typed_failure" || Boolean(terminalErrorCode);
  const liveFinalAnswer = readLatestAuthoritativeFinalLiveEventText(reply);
  const terminalResolution = resolveHelixVisibleTerminalCore(reply);
  const terminalAuthorityText = coerceText(terminalAuthorityRecord?.terminal_text_preview).trim();
  const selectedFinalAnswerCandidate =
    isTypedFailure
      ? terminalAuthorityText || terminalResolution.text || renderTypedFailureFallback(terminalErrorCode)
      : terminalAuthorityTrusted && terminalAuthorityText
        ? terminalAuthorityText
        : "";
  const canonicalGoalKind = readHelixCanonicalGoalKind(reply);
  const terminalArtifactKind =
    coerceText(summary?.terminal_artifact_kind).trim() ||
    coerceText(replyRecord?.terminal_artifact_kind).trim() ||
    coerceText(debugRecord?.terminal_artifact_kind).trim() ||
    coerceText(terminalAuthorityRecord?.terminal_artifact_kind).trim();
  const situationContextAnswer =
    finalAnswerSource === "artifact_synthesis" && terminalArtifactKind === "situation_context_pack"
      ? (
          coerceText(replyRecord?.assistant_answer).trim() ||
          coerceText(replyRecord?.answer).trim() ||
          coerceText(replyRecord?.text).trim() ||
          liveFinalAnswer
        )
      : "";
  const canonicalSelectedFinalAnswer =
    !isTypedFailure && terminalArtifactKind === "model_synthesized_answer" && finalAnswerSource === "final_answer_draft"
      ? (
          coerceText(replyRecord?.selected_final_answer).trim() ||
          coerceText(debugRecord?.selected_final_answer).trim()
        )
      : "";
  const selectedFinalAnswerRaw =
    canonicalSelectedFinalAnswer
      ? canonicalSelectedFinalAnswer
      : terminalResolution.text &&
    terminalResolution.source !== "legacy_shadow" &&
    terminalResolution.source !== "empty" &&
    terminalResolution.source !== "typed_failure"
      ? terminalResolution.text
      : terminalResolution.source === "typed_failure"
      ? terminalResolution.text
      : situationContextAnswer
        ? situationContextAnswer
      : !isTypedFailure && liveFinalAnswer && isInvalidTerminalAnswerText(selectedFinalAnswerCandidate)
      ? liveFinalAnswer
      : selectedFinalAnswerCandidate;
  const selectedFinalAnswer =
    renderDocOpenTerminalFromLocationText({
      text: selectedFinalAnswerRaw,
      goalKind: canonicalGoalKind,
      terminalKind: terminalArtifactKind,
    }) ?? selectedFinalAnswerRaw;
  const routeLabel =
    coerceText(summary?.resolved_route_label).trim() ||
    `${canonicalGoalKind} / ${finalAnswerSource}`;
  return {
    active_turn_id: coerceText(reply.turn_id).trim() || coerceText(summary?.turn_id).trim() || reply.id,
    primary_route_label: routeLabel,
    primary_terminal_label: normalizedStatus,
    primary_source_label: formatHelixVisibleTerminalSourceLabel({
      terminalArtifactKind,
      finalAnswerSource,
    }),
    selected_final_answer: selectedFinalAnswer,
    terminal_error_code: terminalErrorCode,
    pending_server_request_present: pendingPresent,
  };
}

export function chooseVisibleFinalText(reply: HelixAskReply): string {
  const visible = buildVisibleResolvedTurn(reply);
  const replyRecord = readAgentLoopAuditRecord(reply);
  if (visible.primary_source_label.replace(/\s+/g, "_") === "typed_failure" || visible.terminal_error_code) {
    return visible.selected_final_answer || renderTypedFailureFallback(visible.terminal_error_code);
  }
  if (!visible.selected_final_answer && replyRecord?.ok === false) {
    return renderTypedFailureFallback("terminal_authority_missing");
  }
  return visible.selected_final_answer || "";
}

const renderTypedFailureFallback = (code?: string | null): string => {
  const normalized = coerceText(code).trim();
  if (normalized === "synthesis_unavailable") {
    return "I found candidate evidence, but no current-turn synthesis artifact answered the requested conclusion.\nCause: synthesis_unavailable.";
  }
  if (normalized === "equation_source_unavailable") {
    return "I looked for an equation-bearing source, but no current-turn equation artifact satisfied the source contract.\nCause: equation_source_unavailable.";
  }
  return normalized ? `I could not complete that turn.\nCause: ${normalized}.` : "I could not complete that turn.";
};

const readTerminalAnswerAuthorityRecord = (value: unknown): Record<string, unknown> | null => {
  const record = readAgentLoopAuditRecord(value);
  return record?.schema === "helix.turn_terminal_authority.v1" && record.server_authoritative === true
    ? record
    : null;
};

const readTerminalSourceLabelCandidate = (
  record: Record<string, unknown> | null | undefined,
  fallbackFinalAnswerSource?: string | null,
): string | null => {
  const terminalKind =
    typeof record?.terminal_artifact_kind === "string" && record.terminal_artifact_kind.trim()
      ? record.terminal_artifact_kind.trim()
      : null;
  const recordSource =
    typeof record?.final_answer_source === "string" && record.final_answer_source.trim()
      ? record.final_answer_source.trim()
      : null;
  if (!terminalKind && !recordSource) return null;
  return formatHelixVisibleTerminalSourceLabel({
    terminalArtifactKind: terminalKind,
    finalAnswerSource: recordSource ?? fallbackFinalAnswerSource,
  });
};

export function readHelixAskFinalAnswerSourceLabel(...sources: unknown[]): string | null {
  for (const source of sources) {
    const record = readAgentLoopAuditRecord(source);
    if (!record) continue;
    const finalAnswerDraft = readAgentLoopAuditRecord(record.final_answer_draft);
    const finalAnswerDraftAuthority =
      typeof finalAnswerDraft?.authority === "string" && finalAnswerDraft.authority.trim()
        ? finalAnswerDraft.authority.trim()
        : null;
    if (finalAnswerDraftAuthority === "deterministic_receipt_fallback") {
      return "deterministic receipt fallback";
    }
    const directSource =
      typeof record.final_answer_source === "string" && record.final_answer_source.trim()
        ? record.final_answer_source.trim()
        : null;
    const resolvedSummary = readAgentLoopAuditRecord(record.resolved_turn_summary);
    const terminalAuthorityRecord = readTerminalAnswerAuthorityRecord(record.terminal_answer_authority);
    const debugRecord = readAgentLoopAuditRecord(record.debug);
    const debugResolvedSummary = readAgentLoopAuditRecord(debugRecord?.resolved_turn_summary);
    const debugTerminalAuthorityRecord = readTerminalAnswerAuthorityRecord(debugRecord?.terminal_answer_authority);
    for (const terminalRecord of [
      resolvedSummary,
      terminalAuthorityRecord,
      debugResolvedSummary,
      debugTerminalAuthorityRecord,
    ]) {
      const label = readTerminalSourceLabelCandidate(terminalRecord, directSource);
      if (label) return label;
    }
    const directTerminalKind =
      typeof record.terminal_artifact_kind === "string" && record.terminal_artifact_kind.trim()
        ? record.terminal_artifact_kind.trim()
        : null;
    if (directSource || directTerminalKind) {
      return formatHelixVisibleTerminalSourceLabel({
        terminalArtifactKind: directTerminalKind,
        finalAnswerSource: directSource,
      });
    }
    const truthTable = readAgentLoopAuditRecord(record.turn_truth_table);
    const truthTerminal = readAgentLoopAuditRecord(truthTable?.terminal);
    const truthSource =
      typeof truthTerminal?.final_answer_source === "string" && truthTerminal.final_answer_source.trim()
        ? truthTerminal.final_answer_source.trim()
        : null;
    const truthTerminalKind =
      typeof truthTerminal?.kind === "string" && truthTerminal.kind.trim()
        ? truthTerminal.kind.trim()
        : typeof truthTerminal?.terminal_artifact_kind === "string" && truthTerminal.terminal_artifact_kind.trim()
          ? truthTerminal.terminal_artifact_kind.trim()
          : null;
    if (truthSource || truthTerminalKind) {
      return formatHelixVisibleTerminalSourceLabel({
        terminalArtifactKind: truthTerminalKind,
        finalAnswerSource: truthSource,
      });
    }
    const audit = readAgentLoopAuditRecord(record.agent_loop_audit);
    const auditSource =
      typeof audit?.final_answer_source === "string" && audit.final_answer_source.trim()
        ? audit.final_answer_source.trim()
        : null;
    const auditTerminalKind =
      typeof audit?.terminal_artifact_kind === "string" && audit.terminal_artifact_kind.trim()
        ? audit.terminal_artifact_kind.trim()
        : null;
    if (auditSource || auditTerminalKind) {
      return formatHelixVisibleTerminalSourceLabel({
        terminalArtifactKind: auditTerminalKind,
        finalAnswerSource: auditSource,
      });
    }
  }
  return null;
}

export type HelixAskFinalAnswerPresentation = {
  heading: "Final answer" | "Checkpoint receipt";
  sourceLabel: string | null;
  isDeterministicReceiptFallback: boolean;
};

export function isHelixAskDeterministicReceiptFallbackLabel(value: unknown): boolean {
  return /^deterministic[\s_-]+receipt[\s_-]+fallback$/i.test(coerceText(value).trim());
}

export function resolveHelixAskFinalAnswerPresentation(
  sourceLabel: string | null | undefined,
): HelixAskFinalAnswerPresentation {
  if (isHelixAskDeterministicReceiptFallbackLabel(sourceLabel)) {
    return {
      heading: "Checkpoint receipt",
      sourceLabel: "checkpoint receipt (not reviewed)",
      isDeterministicReceiptFallback: true,
    };
  }
  const normalized = coerceText(sourceLabel).trim();
  return {
    heading: "Final answer",
    sourceLabel: normalized || null,
    isDeterministicReceiptFallback: false,
  };
}

function resolveHelixAskVisibleTerminal(value: unknown, fallbackContent?: string | null): HelixAskVisibleTerminalResolution {
  const terminal = resolveHelixVisibleTerminalCore(value, fallbackContent);
  return {
    text: terminal.text,
    source: terminal.source,
    backendTerminalText: terminal.backendTerminalText,
  };
}

function readAgentLoopAuditArray(value: unknown): unknown[] {
  return Array.isArray(value) ? value : [];
}

function readHelixRuntimeArtifactRefs(record: Record<string, unknown>): string[] {
  const refs = [
    record.observed_artifact_refs,
    record.artifact_refs,
    record.produced_artifacts,
    record.actual_artifacts,
    record.consumed_artifact_refs,
  ].flatMap((value) => (Array.isArray(value) ? value : []));
  return Array.from(new Set(refs.map((entry) => coerceText(entry).trim()).filter(Boolean)));
}

function summarizeHelixRuntimeArtifactRefs(refs: string[]): string {
  if (refs.length === 0) return "";
  const labels = refs.map((ref) => {
    if (/workstation[-_]tool[-_]eval|workstation_tool_evaluation/i.test(ref)) {
      return "workstation_tool_evaluation";
    }
    if (/theory[-_]ideology[-_]bridge|helix_theory_ideology_bridge_tool_result/i.test(ref)) {
      return "theory_ideology_bridge evidence";
    }
    const match = ref.match(
      /\b(?:doc_search_results|doc_summary|doc_open_receipt|doc_location_matches|calculator_receipt|workspace_action_receipt|note_update_receipt|runtime_tool_observation|tool_observation|final_answer_draft|direct_answer_text)\b/i,
    );
    if (match?.[0]) return match[0];
    const parts = ref.split(/[/:#]/).map((part) => part.trim()).filter(Boolean);
    const label = parts[parts.length - 1] ?? ref;
    return /^[a-f0-9]{12,}$/i.test(label) || /^\d+$/.test(label) ? "" : label;
  });
  const unique = Array.from(new Set(labels.filter(Boolean)));
  const visible = unique.slice(0, 5).join(", ");
  return unique.length > 5 ? `${visible}, +${unique.length - 5} more` : visible;
}

function buildHelixRuntimeTranscriptEvents(reply: HelixAskReply): Record<string, unknown>[] {
  const replyRecord = readAgentLoopAuditRecord(reply);
  const debugRecord = readAgentLoopAuditRecord(reply.debug);
  const agentRuntimeLoop = readAgentLoopAuditRecord(
    replyRecord?.agent_runtime_loop ?? debugRecord?.agent_runtime_loop,
  );
  const iterations = readAgentLoopAuditArray(agentRuntimeLoop?.iterations);
  if (iterations.length === 0) return [];

  const turnId = coerceText(replyRecord?.turn_id ?? debugRecord?.turn_id ?? reply.id).trim();
  const events: Record<string, unknown>[] = [];
  iterations.slice(0, 24).forEach((item, index) => {
    const record = readAgentLoopAuditRecord(item);
    if (!record) return;
    const nextStep = coerceText(record.next_step ?? record.decision ?? "step").trim() || "step";
    const chosenCapability =
      coerceText(record.executed_action_key).trim() ||
      coerceText(record.chosen_capability).trim() ||
      coerceText(record.capability_key).trim() ||
      coerceText(record.tool_key).trim();
    const authority =
      coerceText(record.decision_authority).trim() ||
      coerceText(record.decision_source).trim() ||
      coerceText(record.sampling_mode).trim() ||
      "runtime";
    const decisionId = coerceText(record.decision_id ?? record.decision_ref).trim();
    const stepId = `runtime_${index + 1}`;
    const status =
      record.observation_role === "tool_error" || record.status === "failed"
        ? "failed"
        : nextStep === "ask_user"
          ? "request_input"
          : "completed";
    const refs = readHelixRuntimeArtifactRefs(record);
    const artifactSummary = summarizeHelixRuntimeArtifactRefs(refs);
    const decisionText =
      nextStep === "answer" || chosenCapability === "model.direct_answer"
        ? "Composed final answer from current observations."
        : chosenCapability
          ? `Selected ${chosenCapability}.`
          : `Selected ${nextStep}.`;
    events.push({
      id: `${reply.id}-runtime-${index}-decision`,
      role: "agent",
      type: "decision",
      status,
      text: decisionText,
      detail: chosenCapability || nextStep,
      lane: authority,
      step_id: stepId,
      turn_id: turnId,
      decision_id: decisionId,
      event_source: "agent_runtime_loop",
    });
    if (nextStep === "answer" || chosenCapability === "model.direct_answer") {
      events.push({
        id: `${reply.id}-runtime-${index}-final`,
        role: "agent",
        type: "observation",
        status,
        text: artifactSummary
          ? `Reviewed observed artifacts for terminal answer: ${artifactSummary}.`
          : "Reviewed observed artifacts for terminal answer.",
        detail: chosenCapability || "model.direct_answer",
        lane: authority,
        step_id: stepId,
        turn_id: turnId,
        decision_id: decisionId,
        event_source: "agent_runtime_loop",
      });
      return;
    }
    events.push({
      id: `${reply.id}-runtime-${index}-observation`,
      role: "tool",
      type: "tool_result",
      status,
      text: artifactSummary ? `Observed ${artifactSummary}.` : "Observed selected capability result.",
      detail: chosenCapability || nextStep,
      lane: chosenCapability || "tool",
      step_id: stepId,
      turn_id: turnId,
      decision_id: decisionId,
      event_source: "agent_runtime_loop",
    });
  });
  return events;
}

function buildHelixRuntimeAskLiveEvents(reply: HelixAskReply): AskLiveEventEntry[] {
  return buildHelixRuntimeTranscriptEvents(reply).map((event, index) => ({
    id: coerceText(event.id).trim() || `${reply.id}-runtime-event-${index}`,
    text: coerceText(event.text).trim() || "Helix Ask runtime update",
    tool: coerceText(event.role).trim() || "agent",
    seq: index,
    meta: {
      stage: coerceText(event.type).trim() || "runtime",
      detail: coerceText(event.detail).trim() || null,
      status: coerceText(event.status).trim() || "completed",
      traceId: coerceText(event.trace_id).trim() || null,
      turnKey: coerceText(event.turn_id).trim() || null,
      stepId: coerceText(event.step_id).trim() || null,
      lane: coerceText(event.lane).trim() || null,
      event_source: "agent_runtime_loop",
    },
  }));
}

function readProceduralActionLabel(value: unknown): string {
  const action = readAgentLoopAuditRecord(value);
  if (!action) return "model step";
  const panelId = typeof action.panel_id === "string" && action.panel_id.trim() ? action.panel_id.trim() : "";
  const actionId = typeof action.action_id === "string" && action.action_id.trim() ? action.action_id.trim() : "";
  if (panelId && actionId) return `${panelId}.${actionId}`;
  if (actionId) return actionId;
  return "model step";
}

function readProceduralStatusClass(status: string): string {
  if (status === "completed") return "border-emerald-300/35 bg-emerald-400/10 text-emerald-50";
  if (status === "canceled") return "border-slate-300/25 bg-slate-400/10 text-slate-200";
  if (status === "running") return "animate-pulse border-sky-300/35 bg-sky-400/10 text-sky-50";
  if (status === "suppressed") return "border-amber-300/35 bg-amber-400/10 text-amber-50";
  if (status === "failed") return "border-rose-300/35 bg-rose-400/10 text-rose-50";
  if (status === "pending_input") return "border-blue-300/35 bg-blue-400/10 text-blue-50";
  if (status === "planned") return "border-white/10 bg-white/5 text-slate-300";
  return "border-white/10 bg-white/5 text-slate-300";
}

function renderProceduralTurnTimeline(reply: HelixAskReply): React.ReactNode {
  const replyRecord = readAgentLoopAuditRecord(reply);
  const truthTable = readAgentLoopAuditRecord(reply.debug?.turn_truth_table);
  const plannerContract = readAgentLoopAuditRecord(reply.debug?.planner_contract);
  const runtimeSummary = readAgentLoopAuditRecord(reply.debug?.turn_runtime);
  const agentLoopAudit = readAgentLoopAuditRecord(reply.debug?.agent_loop_audit);
  const uiDebugParityHarness = readAgentLoopAuditRecord(
    replyRecord?.ui_debug_parity_harness ?? reply.debug?.ui_debug_parity_harness,
  );
  const agentRuntimeLoop = readAgentLoopAuditRecord(
    replyRecord?.agent_runtime_loop ?? reply.debug?.agent_runtime_loop,
  );
  const runtimeIterations = readAgentLoopAuditArray(agentRuntimeLoop?.iterations);
  const planItems = readAgentLoopAuditArray(truthTable?.plan_items ?? plannerContract?.plan_items);
  const observations = readAgentLoopAuditArray(truthTable?.runtime_observations ?? runtimeSummary?.observations);
  const appendedSteps = readAgentLoopAuditArray(runtimeSummary?.appended_steps);
  const terminal = readAgentLoopAuditRecord(truthTable?.terminal ?? runtimeSummary?.terminal);
  const selectedTool = readAgentLoopAuditRecord(truthTable?.selected_tool ?? agentLoopAudit?.selected_action);
  const visibleResolvedTurn = buildVisibleResolvedTurn(reply);
  const route = visibleResolvedTurn.primary_route_label;
  const solverController = readAgentLoopAuditRecord(
    replyRecord?.solver_controller_decision ?? reply.debug?.solver_controller_decision,
  );
  const runtimeStopReason =
    typeof agentRuntimeLoop?.stop_reason === "string" ? agentRuntimeLoop.stop_reason.trim() : "";
  const visibleAnswer = typeof truthTable?.visible_answer_text === "string" ? truthTable.visible_answer_text : reply.content;
  const terminalText = typeof terminal?.text === "string" ? terminal.text : "";
  const parityMatchesVisible =
    typeof uiDebugParityHarness?.ui_answer_equals_terminal_authority_text === "boolean"
      ? uiDebugParityHarness.ui_answer_equals_terminal_authority_text
      : typeof uiDebugParityHarness?.ui_answer_equals_selected_final_answer === "boolean"
        ? uiDebugParityHarness.ui_answer_equals_selected_final_answer
        : null;
  const truthMatchesVisible =
    parityMatchesVisible ??
    Boolean(terminalText && visibleAnswer && terminalText.trim() === visibleAnswer.trim());
  const pendingInput =
    visibleResolvedTurn.primary_terminal_label === "pending_input" && visibleResolvedTurn.pending_server_request_present
      ? readHelixTopLevelPendingServerRequest(reply)
      : null;
  const visibleTerminalKind = resolveHelixVisibleTerminalKind({
    reply,
    terminal,
    fallback: "final_answer",
    extraSources: [truthTable, runtimeSummary, agentLoopAudit],
  });
  const showRuntimeStopReason = shouldShowHelixRuntimeStopReason({
    stopReason: runtimeStopReason,
    finalStatus: replyRecord?.final_status ?? reply.debug?.final_status,
    terminalErrorCode: visibleResolvedTurn.terminal_error_code,
    solverDecision: solverController?.decision,
    terminalKind: visibleTerminalKind,
  });

  if (!truthTable && runtimeIterations.length === 0 && planItems.length === 0 && observations.length === 0 && !terminal) {
    return null;
  }

  const rows: Array<{
    key: string;
    label: string;
    detail: string;
    status: string;
  }> = [];

  const runtimeActionLabels: string[] = [];

  runtimeIterations.slice(0, 12).forEach((item, index) => {
    const record = readAgentLoopAuditRecord(item);
    const chosenCapability = typeof record?.chosen_capability === "string" ? record.chosen_capability.trim() : "";
    const executedAction = typeof record?.executed_action_key === "string" ? record.executed_action_key.trim() : "";
    const actionLabel = executedAction || chosenCapability || String(record?.next_step ?? "model step");
    const authority = String(record?.decision_authority ?? record?.decision_source ?? "unknown");
    const producedArtifacts = Array.isArray(record?.produced_artifacts)
      ? (record.produced_artifacts as unknown[]).map((entry) => String(entry)).filter(Boolean).join(", ")
      : "";
    if (executedAction || chosenCapability) runtimeActionLabels.push(executedAction || chosenCapability);
    rows.push({
      key: `runtime-${index}`,
      label: `Runtime ${String(record?.iteration ?? index + 1)}: ${String(record?.next_step ?? "step")}`,
      detail: `${authority}: ${actionLabel}${producedArtifacts ? ` -> ${producedArtifacts}` : ""}`,
      status:
        record?.observation_role === "tool_error" || record?.status === "failed"
          ? "failed"
          : record?.next_step === "ask_user"
            ? "pending_input"
            : "completed",
    });
  });

  if (runtimeIterations.length === 0) {
    planItems.slice(0, 8).forEach((item, index) => {
      const record = readAgentLoopAuditRecord(item);
      const actionLabel = readProceduralActionLabel(record?.action);
      const lane = String(record?.lane ?? "step");
      rows.push({
        key: `plan-${index}`,
        label: `Plan ${index + 1}: ${lane}`,
        detail: actionLabel !== "model step" ? actionLabel : clipText(String(record?.title ?? record?.id ?? "planned step"), 140),
        status: String(record?.status ?? "planned"),
      });
    });
  }

  appendedSteps.slice(0, 6).forEach((item, index) => {
    const record = readAgentLoopAuditRecord(item);
    rows.push({
      key: `append-${index}`,
      label: `Appended step: ${String(record?.step_id ?? "next_step")}`,
      detail: `because ${String(record?.reason ?? "the previous observation needed another tool")}`,
      status: "running",
    });
  });

  observations.slice(-10).forEach((item, index) => {
    const record = readAgentLoopAuditRecord(item);
    const artifact = readAgentLoopAuditRecord(record?.artifact);
    const actionLabel = readProceduralActionLabel(artifact);
    const actualArtifacts = Array.isArray(record?.actual_artifacts)
      ? (record?.actual_artifacts as unknown[]).map((entry) => String(entry)).filter(Boolean).join(", ")
      : "";
    const blockedArtifacts = Array.isArray(record?.blocked_missing_artifacts)
      ? (record?.blocked_missing_artifacts as unknown[]).map((entry) => String(entry)).filter(Boolean).join(", ")
      : "";
    const detail =
      blockedArtifacts
        ? `blocked: missing ${blockedArtifacts}`
        : actualArtifacts
          ? `observed: ${actualArtifacts}`
          : actionLabel !== "model step"
            ? actionLabel
            : String(record?.step_id ?? "observation");
    rows.push({
      key: `observe-${index}`,
      label: `Observed: ${String(record?.step_id ?? "step")}`,
      detail,
      status: String(record?.status ?? "completed"),
    });
  });

  if (terminal) {
    rows.push({
      key: "terminal",
      label: `Terminal: ${visibleTerminalKind}`,
      detail: clipText(
        String(
          pendingInput?.prompt ??
            pendingInput?.text ??
            terminal.text ??
            visibleAnswer ??
            "turn completed",
        ),
        160,
      ),
      status:
        visibleTerminalKind === "pending_input"
          ? "pending_input"
          : visibleTerminalKind === "canceled"
            ? "canceled"
            : "completed",
    });
  }

  return (
    <div className="mt-3 rounded-xl border border-cyan-300/20 bg-cyan-950/15 px-3 py-2 text-xs text-cyan-50">
      <div className="flex flex-wrap items-center justify-between gap-2">
        <p className="text-[10px] uppercase tracking-[0.2em] text-cyan-200">Procedural workspace timeline</p>
        <p className="text-[10px] uppercase tracking-[0.14em] text-cyan-100/70">
          Truth: {truthMatchesVisible ? "backend terminal == visible answer" : "backend terminal != visible answer"}
        </p>
      </div>
      <p className="mt-1 text-[11px] text-cyan-100/80">
        Route: {route}
        {runtimeActionLabels.length > 0
          ? ` | Tool: ${runtimeActionLabels[0]}`
          : selectedTool
            ? ` | Tool: ${readProceduralActionLabel(selectedTool)}`
            : ""}
        {showRuntimeStopReason ? ` | Runtime: ${runtimeStopReason}` : ""}
      </p>
      <div className="mt-2 space-y-1.5">
        {rows.slice(0, 18).map((row, index) => (
          <div key={row.key} className={`rounded-lg border px-2 py-1.5 ${readProceduralStatusClass(row.status)}`}>
            <div className="flex items-start gap-2">
              <span className="mt-0.5 rounded-full bg-black/20 px-1.5 py-0.5 text-[10px] tabular-nums">
                {index + 1}
              </span>
              <div className="min-w-0">
                <p className="font-medium">{row.label}</p>
                <p className="mt-0.5 break-words text-[11px] opacity-80">
                  {row.detail} [{row.status}]
                </p>
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

function resolveHelixTurnTranscriptEvents(reply: HelixAskReply): Record<string, unknown>[] {
  const replyRecord = readAgentLoopAuditRecord(reply);
  const debugRecord = readAgentLoopAuditRecord(reply.debug);
  const finalAnswerSource =
    coerceText(replyRecord?.final_answer_source).trim() ||
    coerceText(debugRecord?.final_answer_source).trim();
  const terminalArtifactKind =
    coerceText(replyRecord?.terminal_artifact_kind).trim() ||
    coerceText(debugRecord?.terminal_artifact_kind).trim() ||
    coerceText(readHelixResolvedTurnSummary(reply)?.terminal_artifact_kind).trim();
  const filterSatisfiedWorkstationArtifacts =
    finalAnswerSource === "workstation_tool_evaluation" ||
    terminalArtifactKind === "workstation_tool_evaluation";
  const normalizeEvents = (events: unknown[]): Record<string, unknown>[] => {
    const records = events
      .map((entry) => readAgentLoopAuditRecord(entry))
      .filter(Boolean) as Record<string, unknown>[];
    const visible = filterSatisfiedWorkstationArtifacts
      ? records.filter((event) => {
          const status = coerceText(event.status).trim().toLowerCase();
          const text = coerceText(event.text).trim();
          const detail = coerceText(event.detail).trim();
          const combined = `${text}\n${detail}`;
          return (
            status !== "request_input" &&
            status !== "final_failure" &&
            !/\b(?:missing_artifacts|missing_required_artifacts|Need user input|Request input|final_failure)\b/i.test(combined)
          );
        })
      : records;
    return dedupeHelixVisibleTranscriptEvents(visible);
  };
  const runtimeEvents = buildHelixRuntimeTranscriptEvents(reply);
  if (runtimeEvents.length > 0) {
    return normalizeEvents(runtimeEvents);
  }
  const directEvents = Array.isArray(reply.debug?.turn_transcript_events)
    ? reply.debug.turn_transcript_events
    : [];
  if (directEvents.length > 0) {
    return normalizeEvents(directEvents);
  }
  const audit = readAgentLoopAuditRecord(reply.debug?.agent_loop_audit);
  const auditEvents = Array.isArray(audit?.turn_transcript_events) ? audit.turn_transcript_events : [];
  return normalizeEvents(auditEvents);
}

type HelixTurnTranscriptRow = {
  key: string;
  role: string;
  label: string;
  text: string;
  meta: string;
  status: string;
};

function readHelixPublicCommentaryEvents(reply: HelixAskReply): Record<string, unknown>[] {
  const replyRecord = readAgentLoopAuditRecord(reply);
  const debugRecord = readAgentLoopAuditRecord(reply.debug);
  const candidates = [
    replyRecord?.public_commentary_timeline,
    debugRecord?.public_commentary_timeline,
    readAgentLoopAuditRecord(debugRecord?.debug_export)?.public_commentary_timeline,
  ];
  const events = candidates.find(Array.isArray);
  if (!Array.isArray(events)) return [];
  const seen = new Set<string>();
  return events
    .map((entry) => readAgentLoopAuditRecord(entry))
    .filter((event): event is Record<string, unknown> => {
      if (!event) return false;
      if (event.schema !== "helix.ask_public_commentary_event.v1") return false;
      if (event.assistant_answer !== false || event.raw_reasoning_included !== false) return false;
      const text = coerceText(event.text).trim();
      if (!text || /^[{[]/.test(text)) return false;
      if (/\b(?:turn_purpose|why_this_capability|expected_artifacts|observation_summary|next_step_reason)\b/i.test(text)) return false;
      const id = coerceText(event.event_id).trim() || text;
      if (seen.has(id)) return false;
      seen.add(id);
      return true;
    });
}

function buildHelixPublicCommentaryTranscriptRows(reply: HelixAskReply): HelixTurnTranscriptRow[] {
  return readHelixPublicCommentaryEvents(reply).map((event, index) => {
    const timing = coerceText(event.timing).trim();
    const certainty = coerceText(event.certainty_class).trim();
    const expected = coerceText(event.expected_artifact).trim();
    const status = coerceText(event.status).trim() || "thinking";
    const label =
      timing === "final_ready"
        ? "Ready"
        : timing === "after_step"
          ? "Checked"
          : timing === "fail_closed"
            ? "Blocked"
            : timing === "before_step"
              ? "Thinking"
              : "Orienting";
    return {
      key: `${reply.id}-public-commentary-${coerceText(event.event_id).trim() || index}`,
      role: "agent",
      label,
      text: coerceText(event.text).trim(),
      meta: [timing, certainty, expected].filter(Boolean).join(" | "),
      status,
    };
  });
}

function readHelixCausalTurnTimeline(reply: HelixAskReply): HelixCausalTurnTimeline | null {
  const debugRecord = readAgentLoopAuditRecord(reply.debug);
  const timelineRecord =
    readAgentLoopAuditRecord(debugRecord?.causal_turn_timeline) ??
    readAgentLoopAuditRecord((reply as Record<string, unknown>).causal_turn_timeline);
  if (!timelineRecord) return null;
  if (timelineRecord.schema !== "helix.causal_turn_timeline.v1") return null;
  if (!Array.isArray(timelineRecord.events)) return null;
  return timelineRecord as HelixCausalTurnTimeline;
}

function readHelixCausalTraceLabel(event: HelixCausalTurnEvent): string {
  if (event.status === "blocked" || event.status === "failed") return "Notice";
  switch (event.stage) {
    case "prompt_received":
      return "Input";
    case "goal_classified":
    case "source_target_decided":
    case "route_label_set":
    case "tool_surface_built":
      return "Setup";
    case "model_step_requested":
    case "model_step_decided":
    case "model_answer_artifact_created":
      return event.stage === "model_step_decided" ? "Decision" : "Thinking";
    case "deterministic_fallback_considered":
    case "deterministic_fallback_used":
      return "Fallback";
    case "runtime_tool_call_validated":
    case "runtime_tool_dispatched":
      return "Working";
    case "tool_observation_created":
    case "repo_evidence_observation_created":
      return "Observation";
    case "coverage_gate_evaluated":
    case "quality_gate_evaluated":
    case "goal_satisfaction_evaluated":
    case "solver_controller_decided":
    case "projection_mismatch_checked":
      return "Gate";
    case "terminal_artifact_materialized":
    case "terminal_artifact_selected":
    case "terminal_candidate_rejected":
      return "Terminal";
    case "visible_response_written":
      return "Final";
    case "debug_export_written":
      return "Debug";
    default:
      return "Trace";
  }
}

function readHelixCausalTraceText(event: HelixCausalTurnEvent): string {
  const publicSummary = coerceText(event.public_summary).trim();
  if (publicSummary) return clipText(publicSummary, 260);

  const parts: string[] = [];
  const decision = coerceText(event.decision).trim();
  const routeLabel = coerceText(event.route_label).trim();
  const sourceTarget = coerceText(event.source_target).trim();
  const capability = coerceText(event.selected_capability ?? event.model_step_capability).trim();
  const reasonCode = coerceText(event.reason_code).trim();
  if (decision) parts.push(humanizeAskLiveEventToken(decision));
  if (capability) parts.push(`Capability: ${humanizeAskLiveEventToken(capability)}`);
  if (routeLabel) parts.push(`Route: ${humanizeAskLiveEventToken(routeLabel)}`);
  if (sourceTarget) parts.push(`Source: ${humanizeAskLiveEventToken(sourceTarget)}`);
  if (event.fallback?.used) {
    parts.push(`Fallback rule: ${humanizeAskLiveEventToken(event.fallback.rule_id ?? "used")}`);
  }
  if (event.terminal?.selected_terminal_artifact_kind) {
    parts.push(`Selected ${humanizeAskLiveEventToken(event.terminal.selected_terminal_artifact_kind)}`);
  }
  if (Array.isArray(event.rejected) && event.rejected.length > 0) {
    const reasons = dedupeStrings(event.rejected.map((entry) => entry.reason)).slice(0, 3);
    parts.push(`Rejected: ${reasons.map(humanizeAskLiveEventToken).join(", ")}`);
  }
  if (reasonCode) parts.push(`Reason: ${humanizeAskLiveEventToken(reasonCode)}`);
  return parts.length ? clipText(parts.join(". "), 260) : humanizeAskLiveEventToken(event.stage);
}

export function buildHelixCausalTurnTraceRows(reply: HelixAskReply): HelixTurnTranscriptRow[] {
  const timeline = readHelixCausalTurnTimeline(reply);
  if (!timeline) return [];
  return timeline.events
    .filter((event) => {
      if (!event || event.raw_content_included !== false || event.assistant_answer !== false) return false;
      return event.stage !== "prompt_received" && event.stage !== "debug_export_written";
    })
    .sort((left, right) => left.sequence - right.sequence)
    .map((event) => {
      const meta = [
        humanizeAskLiveEventToken(event.producer),
        humanizeAskLiveEventToken(event.stage),
        event.status ? humanizeAskLiveEventToken(event.status) : "",
        event.reason_code ? humanizeAskLiveEventToken(event.reason_code) : "",
      ]
        .filter(Boolean)
        .join(" | ");
      return {
        key: `${reply.id}-causal-trace-${event.event_id || event.sequence}`,
        role: event.producer,
        label: readHelixCausalTraceLabel(event),
        text: readHelixCausalTraceText(event),
        meta,
        status: event.status ?? "succeeded",
      };
    });
}

function readHelixCausalTraceRowClass(row: HelixTurnTranscriptRow): string {
  if (/\b(?:failed|blocked)\b/i.test(row.status)) {
    return "border-amber-300/30 bg-amber-950/20 text-amber-50";
  }
  if (row.label === "Final" || row.label === "Terminal") {
    return "border-violet-300/25 bg-violet-950/15 text-violet-50";
  }
  if (row.label === "Observation") {
    return "border-emerald-300/25 bg-emerald-950/15 text-emerald-50";
  }
  if (row.label === "Gate") {
    return "border-cyan-300/25 bg-cyan-950/15 text-cyan-50";
  }
  return "border-slate-600/30 bg-black/15 text-slate-100";
}

export function buildHelixTurnTranscriptRows(reply: HelixAskReply): HelixTurnTranscriptRow[] {
  const publicCommentaryRows = buildHelixPublicCommentaryTranscriptRows(reply);
  const transcriptEvents = resolveHelixTurnTranscriptEvents(reply);
  if (transcriptEvents.length > 0) {
    const lifecycleRows = transcriptEvents
      .filter((event) => {
        const type = String(event.type ?? "");
        const status = String(event.status ?? "");
        if (publicCommentaryRows.length > 0 && (type === "turn_completed" || type === "work_delta")) return false;
        if (publicCommentaryRows.length > 0 && type === "step_started") return false;
        return type !== "question" && type !== "turn_completed" && status !== "superseded";
      })
      .slice(-14)
      .map((event, index) => {
        const role = String(event.role ?? "agent");
        const type = String(event.type ?? "event");
        const status = String(event.status ?? "");
        const actionLabel = resolveHelixTranscriptActionLabel(event);
        const eventText = String(event.text ?? "");
        const rowText =
          actionLabel && !eventText.includes(actionLabel)
            ? `${actionLabel}: ${eventText || type}`
            : eventText;
        const label =
          type === "public_commentary"
            ? "Thinking"
          : type === "plan"
            ? "Plan"
            : type === "model_decision"
              ? status === "running"
                ? "Thinking"
                : "Decision"
            : type === "step_started"
              ? "Working"
              : type === "receipt_pending"
                ? "Working"
              : type === "receipt_observed"
                ? "Observation"
              : type === "tool_result"
                ? "Observation"
                : type === "observation"
                  ? "Recorded"
                  : type === "decision"
                    ? "Decision"
                    : type === "final_answer"
                      ? "Final"
                      : "Agent";
        return {
          key: `${reply.id}-transcript-event-${index}`,
          role,
          label,
          text: rowText,
          meta: [String(event.lane ?? ""), String(event.step_id ?? ""), actionLabel ?? "", status]
            .filter(Boolean)
            .join(" | "),
          status,
        };
      });
    if (publicCommentaryRows.length > 0) {
      const lifecycleWithoutGenericCompletions = lifecycleRows.filter((row) =>
        !/^Completed step\b/i.test(row.text),
      );
      return [...publicCommentaryRows, ...lifecycleWithoutGenericCompletions].slice(-14);
    }
    return lifecycleRows;
  }
  if (publicCommentaryRows.length > 0) return publicCommentaryRows.slice(-14);
  const plannerContract = readAgentLoopAuditRecord(reply.debug?.planner_contract);
  const runtimeSummary = readAgentLoopAuditRecord(reply.debug?.turn_runtime);
  const planItems = Array.isArray(plannerContract?.plan_items) ? plannerContract.plan_items : [];
  const observations = Array.isArray(runtimeSummary?.observations) ? runtimeSummary.observations : [];
  const rows: HelixTurnTranscriptRow[] = [];
  planItems.slice(0, 4).forEach((item, index) => {
    const record = readAgentLoopAuditRecord(item);
    rows.push({
      key: `${reply.id}-fallback-plan-${index}`,
      role: "agent",
      label: "Plan",
      text: String(record?.title ?? record?.id ?? "planned step"),
      meta: `${String(record?.lane ?? "step")} | ${String(record?.status ?? "planned")}`,
      status: String(record?.status ?? "planned"),
    });
  });
  observations.slice(-6).forEach((item, index) => {
    const record = readAgentLoopAuditRecord(item);
    const actualArtifacts = Array.isArray(record?.actual_artifacts)
      ? (record.actual_artifacts as unknown[]).map((entry) => String(entry)).filter(Boolean).join(", ")
      : "";
    rows.push({
      key: `${reply.id}-fallback-observation-${index}`,
      role: "tool",
      label: "Observation",
      text: actualArtifacts || String(record?.step_id ?? "step result"),
      meta: `${String(record?.lane ?? "step")} | ${String(record?.status ?? "completed")}`,
      status: String(record?.status ?? "completed"),
    });
  });
  return rows;
}

