type ReasoningTheaterStance = "winning" | "contested" | "losing" | "fail_closed";
type ReasoningTheaterArchetype =
  | "ambiguity"
  | "missing_evidence"
  | "coverage_gap"
  | "contradiction"
  | "overload";
type ReasoningTheaterSuppressionReason =
  | "context_ineligible"
  | "dedupe_cooldown"
  | "mission_rate_limited"
  | "voice_rate_limited"
  | "voice_budget_exceeded"
  | "voice_backend_error"
  | "missing_evidence"
  | "contract_violation"
  | "agi_overload_admission_control";
type ReasoningTheaterPhase =
  | "observe"
  | "plan"
  | "retrieve"
  | "gate"
  | "synthesize"
  | "verify"
  | "execute"
  | "debrief";
type ReasoningTheaterCertaintyClass =
  | "confirmed"
  | "reasoned"
  | "hypothesis"
  | "unknown";
type ReasoningTheaterMedal =
  | "scout"
  | "anchor"
  | "lattice"
  | "prism"
  | "fracture"
  | "stitch"
  | "relay"
  | "gate"
  | "seal"
  | "lantern"
  | "valve"
  | "crown";

