const shouldSuppressAtomicViewerLaunch = (args: {
  question?: string | null;
  mode?: "read" | "observe" | "act" | "verify";
}): boolean => {
  const question = (args.question ?? "").trim();
  if (!question) return false;
  const docsSummaryCue = HELIX_DOCS_SUMMARY_REQUEST_RE.test(question);
  if (!docsSummaryCue) return false;
  return HELIX_DOCS_VIEWER_CONTEXT_RE.test(question) || HELIX_DOCS_PATH_LITERAL_RE.test(question);
};

function normalizePanelQuery(value: string): string {
  return value.toLowerCase().replace(/[^a-z0-9]+/g, " ").trim();
}

function resolvePanelIdFromText(value: string): PanelDefinition["id"] | null {
  const normalized = normalizePanelQuery(value);
  if (!normalized) return null;
  for (const entry of HELIX_PANEL_ALIASES) {
    if (!getPanelDef(entry.id)) continue;
    if (entry.aliases.some((alias) => normalized.includes(alias))) {
      return entry.id;
    }
  }
  const tokens = normalized.split(/\s+/).filter(Boolean);
  let bestId: PanelDefinition["id"] | null = null;
  let bestScore = 0;
  for (const panel of panelRegistry) {
    if (!getPanelDef(panel.id)) continue;
    const haystack = `${panel.title} ${panel.id} ${(panel.keywords ?? []).join(" ")}`.toLowerCase();
    let score = 0;
    for (const token of tokens) {
      if (haystack.includes(token)) score += 1;
    }
    if (score > bestScore) {
      bestScore = score;
      bestId = panel.id;
    }
  }
  return bestScore > 0 ? bestId : null;
}

function resolvePanelIdFromPath(value: string): PanelDefinition["id"] | null {
  const normalized = value.replace(/\\/g, "/").toLowerCase();
  if ((/(^|\/)docs\//i.test(normalized) || /\.md$/i.test(normalized)) && getPanelDef("docs-viewer")) {
    return "docs-viewer";
  }
  return null;
}

function parseOpenPanelCommand(value: string): PanelDefinition["id"] | null {
  const match = value.trim().match(/^(?:\/open|open|show|launch)\s+(.+)/i);
  if (!match) return null;
  const raw = match[1].replace(/^(the|panel|window)\s+/i, "").trim();
  const lowerRaw = raw.toLowerCase();
  const conversationalDocIntent =
    /\b(?:doc|docs|documentation|paper|report|publication|research)\b/.test(lowerRaw) &&
    /\b(?:about|for|on|regarding)\b/.test(lowerRaw);
  const readAloudIntent = /\b(?:read|aloud|out loud|speak|narrate|voice)\b/.test(lowerRaw);
  if (conversationalDocIntent || readAloudIntent) return null;
  return resolvePanelIdFromText(raw);
}

function restateWorkstationSubgoal(value: string): string {
  const cleaned = value
    .trim()
    .replace(/^["'\s]+|["'\s]+$/g, "")
    .replace(/^question\s*:\s*/i, "")
    .replace(/^(?:hey|hi)\s+(?:helix|dottie)\s*,?\s*/i, "")
    .replace(/^(?:can|could|would)\s+you\s+/i, "")
    .replace(/^please\s+/i, "")
    .trim();
  const summarizeOrExplainIntent =
    /\b(?:summari[sz]e|summary|tldr|tl;dr|explain|break\s+down|walk\s+me\s+through|what\s+does)\b/i.test(
      cleaned,
    );
  if (summarizeOrExplainIntent) {
    return cleaned;
  }
  const paperReadTopic =
    cleaned.match(
      /\b(?:read|open|show|find|search|look|pick|bring|pull)\b[\s\S]*?\b(?:paper|papers|research|publication|report|doc|document)\b[\s\S]*?\b(?:about|on|for|regarding)\s+(.+?)(?:[.?!]|$)/i,
    )?.[1]?.trim() ??
    cleaned.match(/\b(?:paper|papers|doc|document)\s+(?:about|on|for|regarding)\s+(.+?)(?:[.?!]|$)/i)?.[1]?.trim();

  if (paperReadTopic) {
    return `find a paper about ${paperReadTopic} and open it and read it to me`;
  }
  return cleaned;
}

function normalizeWorkstationCommandText(value: string): string {
  const normalizedQuotes = value.replace(/[“”]/g, "\"").replace(/[‘’]/g, "'");
  const collapsedWhitespace = normalizedQuotes.replace(/\s+/g, " ").trim();
  if (!collapsedWhitespace) return "";
  return collapsedWhitespace
    .replace(/\boutloud\b/gi, "out loud")
    .replace(/\b(?:pull|bring)\s+up\b/gi, "open")
    .replace(/\bpop\s+open\b/gi, "open")
    .replace(/\bopen\s+up\b/gi, "open")
    .replace(/\bjump\s+(?:over\s+)?to\b/gi, "go to")
    .replace(/\bread\s+(this|current)\s+to\s+me\b/gi, (_match, referent: string) => {
      return `read ${referent.toLowerCase()} doc to me`;
    })
    .replace(/\bread\s+(this|current)\s+(?:aloud|out\s+loud)\b/gi, (_match, referent: string) => {
      return `read ${referent.toLowerCase()} doc to me`;
    })
    .replace(/\bnarrate\s+(this|current)\s+to\s+me\b/gi, (_match, referent: string) => {
      return `read ${referent.toLowerCase()} doc to me`;
    })
    .replace(/\bnarrate\s+(this|current)\s+(?:aloud|out\s+loud)\b/gi, (_match, referent: string) => {
      return `read ${referent.toLowerCase()} doc to me`;
    })
    .replace(/\b(this|current)\s+file\b/gi, (_match, referent: string) => {
      return `${referent.toLowerCase()} doc`;
    })
    .replace(/\bnote\s*pad\b/gi, "note")
    .replace(/\bnotepad\b/gi, "note")
    .replace(/\bclip\s*board\b/gi, "clipboard")
    .replace(/\bcopy\s+that\s+to\s+clipboard\b/gi, "copy this to clipboard")
    .replace(/\bcopy\s+it\s+to\s+clipboard\b/gi, "copy this to clipboard")
    .replace(/\bappend\s+that\s+to\s+my\s+note\b/gi, "append this to my note")
    .replace(/\s+/g, " ")
    .trim();
}

function supportsPanelAction(panelId: string, actionId: string): boolean {
  const capabilities = getWorkstationPanelCapabilities(panelId);
  if (!capabilities) return false;
  return capabilities.actions.some((action) => action.id === actionId);
}

function buildLexiconPanelAction(
  panelId: string,
  actionId: string,
  args?: Record<string, unknown>,
): HelixWorkstationAction | null {
  if (!supportsPanelAction(panelId, actionId)) return null;
  return {
    action: "run_panel_action",
    panel_id: panelId,
    action_id: actionId,
    args,
  };
}

function normalizeLexiconAlias(value: string): string {
  return value
    .toLowerCase()
    .replace(/\bopen\s+up\b/g, "open")
    .replace(
      /^(?:ok|okay|please|pls|can\s+you|could\s+you|would\s+you|will\s+you|let'?s|kindly)\b[\s,.-]*/g,
      "",
    )
    .replace(/\b(?:the|my)\b/g, " ")
    .replace(/[^a-z0-9]+/g, " ")
    .trim();
}

function resolveCapabilityAliasPanelAction(source: string): HelixWorkstationAction | null {
  const normalizedSource = normalizeLexiconAlias(source);
  if (!normalizedSource) return null;
  for (const [panelId, capabilities] of Object.entries(WORKSTATION_V1_PANEL_CAPABILITIES)) {
    for (const action of capabilities.actions) {
      const aliases = Array.isArray(action.aliases) ? action.aliases : [];
      const requiresArgs = Array.isArray(action.required_args) && action.required_args.length > 0;
      if (requiresArgs) continue;
      for (const alias of aliases) {
        const normalizedAlias = normalizeLexiconAlias(alias);
        if (!normalizedAlias) continue;
        if (
          normalizedAlias === normalizedSource ||
          normalizedSource === `${normalizedAlias} now` ||
          normalizedSource.startsWith(`${normalizedAlias} please`) ||
          normalizedSource.startsWith(`${normalizedAlias} for me`)
        ) {
          return {
            action: "run_panel_action",
            panel_id: panelId,
            action_id: action.id,
            args: undefined,
          };
        }
      }
    }
  }
  return null;
}

function parseWorkstationLexiconAction(
  source: string,
  conversationalCandidate: string,
): HelixWorkstationAction | null {
  const normalized = source.toLowerCase();

  const explicitDocPathMatch = conversationalCandidate.match(
    /\b(?:open|view|show|read|pull\s+up)\s+(\/?docs\/[^\s]+?\.(?:md|mdx|txt|rst|adoc))(?:[?.!])?$/i,
  );
  if (explicitDocPathMatch) {
    const path = explicitDocPathMatch[1]?.replace(/[?.!]+$/g, "").trim();
    if (path) {
      return buildLexiconPanelAction("docs-viewer", "open_doc_by_path", { path });
    }
  }

  const latestDocMatch =
    conversationalCandidate.match(/\b(?:open|view|show|read|pick|grab|pull\s+up)\s+(?:the\s+)?(?:latest|newest|most\s+recent)\s+(.+?)\s+(?:doc|docs|document|paper)\b/i) ??
    conversationalCandidate.match(/\b(?:open|view|show|read|pick|grab|pull\s+up)\s+(?:the\s+)?(.+?)\s+(?:latest|newest|most\s+recent)\s+(?:doc|docs|document|paper)\b/i);
  if (latestDocMatch) {
    const topic = latestDocMatch[1]
      ?.replace(/\b(?:the|a|an|doc|docs|document|paper|latest|newest|most|recent)\b/gi, " ")
      .replace(/[?.!]+$/g, "")
      .replace(/\s+/g, " ")
      .trim();
    if (topic) {
      return buildLexiconPanelAction("docs-viewer", "open_latest_doc_by_topic", { topic });
    }
  }

  if (/^(?:ok|okay|please\s+)?(?:list|show)\s+(?:my\s+)?notes\b/i.test(conversationalCandidate)) {
    return buildLexiconPanelAction("workstation-notes", "list_notes");
  }

  const createNoteMatch =
    conversationalCandidate.match(/\bcreate\s+(?:a\s+)?note\s+(?:called|named|titled)\s+(.+)$/i) ??
    conversationalCandidate.match(/\bnew\s+note\s+(.+)$/i) ??
    conversationalCandidate.match(/\bstart\s+note\s+(?:about|on|for)\s+(.+)$/i);
  if (createNoteMatch) {
    const title = createNoteMatch[1]?.replace(/[?.!]+$/g, "").trim();
    if (title) {
      return buildLexiconPanelAction("workstation-notes", "create_note", { title, topic: title });
    }
  }

  const appendToMyNoteMatch =
    conversationalCandidate.match(/\bappend\s+this\s+to\s+my\s+note\b[:\s-]*(.+)$/i) ??
    conversationalCandidate.match(/\bappend\s+to\s+my\s+note\b[:\s-]*(.+)$/i);
  if (appendToMyNoteMatch) {
    const text = appendToMyNoteMatch[1]?.replace(/[?.!]+$/g, "").trim();
    if (text) {
      return buildLexiconPanelAction("workstation-notes", "append_to_note", { text });
    }
  }

  const appendNamedMatch = conversationalCandidate.match(/\badd\s+to\s+note\s+(.+?)\s*:\s*(.+)$/i);
  if (appendNamedMatch) {
    const title = appendNamedMatch[1]?.trim();
    const text = appendNamedMatch[2]?.trim();
    if (title && text) {
      return buildLexiconPanelAction("workstation-notes", "append_to_note", { title, text });
    }
  }

  const appendTextToNamedNoteMatch = conversationalCandidate.match(
    /\b(?:append|add|put|save|write)\s+(.+?)\s+\b(?:to|into|in)\s+(?:the\s+|my\s+)?(?:note|notepad)\s+(.+)$/i,
  );
  if (appendTextToNamedNoteMatch) {
    const text = appendTextToNamedNoteMatch[1]?.replace(/[?.!]+$/g, "").trim();
    const title = appendTextToNamedNoteMatch[2]?.replace(/[?.!]+$/g, "").trim();
    if (title && text) {
      return buildLexiconPanelAction("workstation-notes", "append_to_note", { title, text });
    }
  }

  const activateNoteMatch = conversationalCandidate.match(/\b(?:open|switch\s+to|select)\s+note\s+(.+)$/i);
  if (activateNoteMatch) {
    const title = activateNoteMatch[1]?.replace(/[?.!]+$/g, "").trim();
    if (title) {
      return buildLexiconPanelAction("workstation-notes", "set_active_note", { title });
    }
  }

  const renameNoteMatch = conversationalCandidate.match(/\brename\s+note\s+(.+?)\s+to\s+(.+)$/i);
  if (renameNoteMatch) {
    const fromTitle = renameNoteMatch[1]?.trim();
    const title = renameNoteMatch[2]?.replace(/[?.!]+$/g, "").trim();
    if (fromTitle && title) {
      return buildLexiconPanelAction("workstation-notes", "rename_note", {
        from_title: fromTitle,
        title,
      });
    }
  }

  const deleteNoteMatch = conversationalCandidate.match(/\bdelete\s+note\s+(.+)$/i);
  if (deleteNoteMatch) {
    const title = deleteNoteMatch[1]?.replace(/[?.!]+$/g, "").trim();
    if (title) {
      return buildLexiconPanelAction("workstation-notes", "delete_note", { title });
    }
  }

  const deicticCopyToNoteMatch = conversationalCandidate.match(
    /\bcopy\s+(?:this|that|current)\s+(?:abstract|section|excerpt|snippet|selection|text|content)\s+to\s+(?:a\s+)?(?:note|notes|note\s+pad)(?:\s+(?:called|named|titled)\s+(.+))?$/i,
  );
  if (deicticCopyToNoteMatch) {
    const noteTitle = deicticCopyToNoteMatch[1]?.replace(/[?.!]+$/g, "").trim();
    return buildLexiconPanelAction("workstation-clipboard-history", "copy_selection_to_note", {
      note_title: noteTitle || undefined,
    });
  }

  if (/\bread\s+clipboard\b/i.test(normalized)) {
    return buildLexiconPanelAction("workstation-clipboard-history", "read_clipboard");
  }

  const copyToClipboardMatch = conversationalCandidate.match(
    /\bcopy\s+this\s+to\s+clipboard\b[:\s-]*(.+)?$/i,
  );
  if (copyToClipboardMatch) {
    const text = copyToClipboardMatch[1]?.replace(/[?.!]+$/g, "").trim();
    if (text) {
      return buildLexiconPanelAction("workstation-clipboard-history", "write_clipboard", { text });
    }
  }

  if (/\bclear\s+clipboard\s+history\b/i.test(normalized) || /\bclear\s+clipboard\b/i.test(normalized)) {
    return buildLexiconPanelAction("workstation-clipboard-history", "clear_history");
  }

  const copyReceiptToNoteMatch = conversationalCandidate.match(
    /\bcopy\s+(?:latest\s+)?clipboard\s+entry\s+to\s+note\s+(.+)$/i,
  );
  if (copyReceiptToNoteMatch) {
    const noteTitle = copyReceiptToNoteMatch[1]?.replace(/[?.!]+$/g, "").trim();
    return buildLexiconPanelAction("workstation-clipboard-history", "copy_receipt_to_note", {
      note_title: noteTitle || undefined,
    });
  }

  if (
    /\bcopy\s+(?:latest\s+)?clipboard\s+entry\s+to\s+clipboard\b/i.test(normalized) ||
    /\bcopy\s+receipt\s+to\s+clipboard\b/i.test(normalized)
  ) {
    return buildLexiconPanelAction("workstation-clipboard-history", "copy_receipt_to_clipboard");
  }

  const capabilityAliasMatch = resolveCapabilityAliasPanelAction(conversationalCandidate);
  if (capabilityAliasMatch) return capabilityAliasMatch;

  return null;
}

export function parseWorkstationActionChainCommand(value: string): HelixWorkstationAction[] | null {
  const trimmed = normalizeWorkstationCommandText(value);
  if (!trimmed) return null;
  const conversationalCandidate = restateWorkstationSubgoal(trimmed);
  const normalized = conversationalCandidate.toLowerCase();
  const hasCopySelectionSignal = /\bcopy\s+(?:this|that|current)\s+(?:abstract|section|excerpt|snippet|selection|text|content)\b/i.test(
    normalized,
  );
  const hasNoteSignal = /\b(?:to\s+(?:a\s+)?note|to\s+notes?)\b/i.test(normalized);
  const hasCompareSignal = /\b(?:compare|contrast|difference|overlap|synthesi[sz]e|explain)\b/i.test(normalized);
  if (!(hasCopySelectionSignal && hasNoteSignal && hasCompareSignal)) return null;

  const noteTitle =
    conversationalCandidate.match(/\bto\s+(?:a\s+)?note\s+(?:called|named|titled)\s+(.+?)(?:\s+(?:and|then)\b|$)/i)?.[1]?.trim() ??
    conversationalCandidate.match(/\bto\s+note\s+(.+?)(?:\s+(?:and|then)\b|$)/i)?.[1]?.trim() ??
    undefined;
  const compareInstruction =
    conversationalCandidate.match(/\b(?:and|then)\s+(compare[\s\S]*)$/i)?.[1]?.trim() ??
    "Compare the note with the current docs context and explain the key differences.";
  const copySelectionAction = buildLexiconPanelAction("workstation-clipboard-history", "copy_selection_to_note", {
    note_title: noteTitle,
  });
  if (!copySelectionAction) return null;

  const compareJobAction: HelixWorkstationAction = {
    action: "run_job",
    payload: {
      workflow: "observable_research_pipeline",
      title: noteTitle ? `Compare note ${noteTitle} with current doc` : "Compare copied selection with current doc",
      objective:
        "Compose a comparison between the copied selection note and current docs-viewer context, then explain it plainly.",
      preferred_panels: ["workstation-notes", "docs-viewer", "workstation-workflow-timeline"],
      max_steps: 5,
      workflow_args: {
        note_title: noteTitle,
        compare_instruction: compareInstruction,
        compare_basis: "current_doc",
        chain_signature: "copy_selection_to_note -> compare_note_with_doc",
      },
    },
  };
  return [copySelectionAction, compareJobAction];
}

export function parseWorkstationActionCommand(value: string): HelixWorkstationAction | null {
  const trimmed = normalizeWorkstationCommandText(value);
  if (!trimmed) return null;
  const conversationalCandidate = restateWorkstationSubgoal(trimmed);
  const conversationalCommand = conversationalCandidate
    .replace(/[?.!,;:]+$/g, "")
    .replace(/^["'`\s]+|["'`\s]+$/g, "")
    .trim();
  const deterministicFrameDecision = inferDeterministicWorkstationIntentDecision(conversationalCommand);
  const deterministicFrameAction = deterministicFrameDecision
    ? coerceWorkstationActionFromIntentDecision(deterministicFrameDecision)
    : null;
  if (
    deterministicFrameAction &&
    (deterministicFrameAction.action === "close_active_panel" ||
      deterministicFrameAction.action === "focus_next_panel" ||
      deterministicFrameAction.action === "focus_previous_panel" ||
      deterministicFrameAction.action === "reopen_last_closed_panel")
  ) {
    return deterministicFrameAction;
  }
  const lexiconAction = parseWorkstationLexiconAction(trimmed, conversationalCandidate);
  if (lexiconAction) return lexiconAction;

  const parsePayloadToJob = (
    payload: Record<string, unknown>,
  ): {
    title?: string;
    objective?: string;
    preferred_panels?: string[];
    max_steps?: number;
    workflow?: "observable_research_pipeline";
    workflow_args?: Record<string, unknown>;
  } => {
    const title = typeof payload.title === "string" ? payload.title.trim() : "";
    const objective = typeof payload.objective === "string" ? payload.objective.trim() : "";
    const preferredPanels = Array.isArray(payload.preferred_panels)
      ? payload.preferred_panels
          .filter((entry) => typeof entry === "string")
          .map((entry) => (entry as string).trim())
          .filter(Boolean)
      : [];
    const maxSteps =
      typeof payload.max_steps === "number" && Number.isFinite(payload.max_steps)
        ? Math.max(1, Math.min(12, Math.floor(payload.max_steps)))
        : undefined;
    const workflow =
      typeof payload.workflow === "string" && payload.workflow.trim() === "observable_research_pipeline"
        ? "observable_research_pipeline"
        : undefined;
    const workflowArgs =
      payload.workflow_args && typeof payload.workflow_args === "object" && !Array.isArray(payload.workflow_args)
        ? (payload.workflow_args as Record<string, unknown>)
        : undefined;
    return {
      ...(title ? { title } : {}),
      ...(objective ? { objective } : {}),
      ...(preferredPanels.length > 0 ? { preferred_panels: preferredPanels } : {}),
      ...(typeof maxSteps === "number" ? { max_steps: maxSteps } : {}),
      ...(workflow ? { workflow } : {}),
      ...(workflowArgs ? { workflow_args: workflowArgs } : {}),
    };
  };

  const parseNaturalLanguageRunJob = (
    source: string,
  ): {
    title?: string;
    objective?: string;
    preferred_panels?: string[];
    max_steps?: number;
    workflow?: "observable_research_pipeline";
    workflow_args?: Record<string, unknown>;
  } => {
    const payload: {
      title?: string;
      objective?: string;
      preferred_panels?: string[];
      max_steps?: number;
      workflow?: "observable_research_pipeline";
      workflow_args?: Record<string, unknown>;
    } = {};
    const text = source.trim();
    const objectiveQuoted =
      text.match(/\bobjective\s*[:=]?\s*"([^"]+)"/i)?.[1]?.trim() ??
      text.match(/\bobjective\s*[:=]?\s*'([^']+)'/i)?.[1]?.trim();
    if (objectiveQuoted) {
      payload.objective = objectiveQuoted;
    } else {
      const objectiveBare = text.match(/\bobjective\s*[:=]?\s*([^,]+)(?:,|$)/i)?.[1]?.trim();
      if (objectiveBare) payload.objective = objectiveBare.replace(/\.$/, "").trim();
    }

    const titleQuoted =
      text.match(/\btitle\s*[:=]?\s*"([^"]+)"/i)?.[1]?.trim() ??
      text.match(/\btitle\s*[:=]?\s*'([^']+)'/i)?.[1]?.trim();
    if (titleQuoted) payload.title = titleQuoted;

    const preferredPanelsMatch = text.match(/\bpreferred_panels\s*[:=]?\s*(\[[^\]]*\])/i)?.[1];
    if (preferredPanelsMatch) {
      try {
        const parsed = JSON.parse(preferredPanelsMatch) as unknown;
        if (Array.isArray(parsed)) {
          const normalized = parsed
            .filter((entry) => typeof entry === "string")
            .map((entry) => (entry as string).trim())
            .filter(Boolean);
          if (normalized.length > 0) payload.preferred_panels = normalized;
        }
      } catch {
        // ignore malformed preferred_panels arrays
      }
    }

    const maxStepsText = text.match(/\bmax_steps\s*[:=]?\s*(\d{1,2})\b/i)?.[1];
    if (maxStepsText) {
      const parsed = Number(maxStepsText);
      if (Number.isFinite(parsed)) {
        payload.max_steps = Math.max(1, Math.min(12, Math.floor(parsed)));
      }
    }

    if (/\bobservable_research_pipeline\b/i.test(text)) {
      payload.workflow = "observable_research_pipeline";
    }
    return payload;
  };

  const parseObservableResearchPipelineCommand = (
    source: string,
  ): {
    topic: string;
    note_title: string;
    compare_instruction: string;
  } | null => {
    const normalized = source.trim();
    if (!normalized) return null;
    const hasCopySignal = /\b(?:copy|collect|grab)\b/i.test(normalized);
    const hasDocsSignal = /\b(?:doc|docs|document|paper|section)\b/i.test(normalized);
    const hasNoteSignal = /\b(?:note|notepad|notes)\b/i.test(normalized);
    const hasCompareSignal = /\b(?:compare|explain|analysis|difference|overlap)\b/i.test(normalized);
    if (!hasCopySignal || !hasDocsSignal || !hasNoteSignal || !hasCompareSignal) return null;

    const topic =
      normalized.match(/\b(?:about|on|for|regarding)\s+(.+?)(?=\s+(?:in|into|to)\s+(?:doc|docs|note|notes)|\s*(?:,|;|\.|$))/i)?.[1]?.trim() ??
      normalized.match(/\btopic\s*[:=]?\s*["']?(.+?)["']?(?=\s*(?:,|;|\.|$))/i)?.[1]?.trim() ??
      "requested topic";

    const noteTitle =
      normalized.match(/\bnotes?\s+([a-z0-9 _-]{2,80})/i)?.[1]?.trim() ??
      `Topic note: ${topic}`;

    const compareInstruction =
      normalized.match(/\bcompare[\s\S]*$/i)?.[0]?.trim() ??
      `Compare the collected sections about ${topic} and write a plain-language explanation.`;

    return {
      topic,
      note_title: noteTitle,
      compare_instruction: compareInstruction,
    };
  };

  const resolveDocPathFromPrompt = (source: string, options?: { useTopicHints?: boolean }): string | null => {
    const explicitPath = source.match(/\b(docs\/[a-z0-9._/-]+\.(?:md|json))\b/i)?.[1]?.trim();
    if (explicitPath) return explicitPath;
    if (options?.useTopicHints !== false) {
      for (const hint of HELIX_DOC_TOPIC_PATH_HINTS) {
        if (hint.pattern.test(source)) return hint.path;
      }
    }
    return null;
  };

  const resolveDocOpenArgs = (
    topic: string,
    hintedPath: string,
  ): {
    path: string;
    meta?: {
      status: "weak" | "ambiguous";
      confidence: number;
      topic: string | null;
      candidates: string[];
    };
  } | null => {
    if (hintedPath) return { path: hintedPath };
    const cleanedTopic = topic.trim();
    if (!cleanedTopic) return null;
    const resolution = resolveDocTopic(cleanedTopic);
    if (!resolution.best?.route) return null;
    if (resolution.status === "strong") {
      return { path: resolution.best.route };
    }
    return {
      path: resolution.best.route,
      meta: {
        status: resolution.status === "ambiguous" ? "ambiguous" : "weak",
        confidence: resolution.confidence,
        topic: cleanedTopic,
        candidates: resolution.candidates.map((candidate) => candidate.route).filter((candidate) => Boolean(candidate)),
      },
    };
  };

  const jsonActionMatch = trimmed.match(
    /^(?:\/(?:workstation|action)|workstation|action)\s*:?\s*(\{[\s\S]+\})$/i,
  );
  if (jsonActionMatch) {
    try {
      const parsed = JSON.parse(jsonActionMatch[1]) as unknown;
      const actions = coerceHelixWorkstationActions(parsed);
      if (actions.length > 0) return actions[0] ?? null;
    } catch {
      // ignore malformed structured delegation envelopes
    }
  }

  const runJobMatch = trimmed.match(/^\/run-job(?:\s+(.+))?$/i);
  if (runJobMatch) {
    const rawPayload = runJobMatch[1]?.trim();
    let payload: {
      title?: string;
      objective?: string;
      preferred_panels?: string[];
      max_steps?: number;
    } = {};
    if (rawPayload) {
      try {
        const parsed = JSON.parse(rawPayload) as Record<string, unknown>;
        if (parsed && typeof parsed === "object" && !Array.isArray(parsed)) {
          payload = parsePayloadToJob(parsed);
        }
      } catch {
        payload = {
          objective: rawPayload,
        };
      }
    }
    return {
      action: "run_job",
      payload,
    };
  }

  const naturalRunJobMatch = conversationalCandidate.match(
    /^(?:run|start|execute)\s+(?:a\s+)?workstation\s+job\b[:\s,-]*(.*)$/i,
  );
  if (naturalRunJobMatch) {
    const extracted = parseNaturalLanguageRunJob(naturalRunJobMatch[1] ?? "");
    return {
      action: "run_job",
      payload: extracted,
    };
  }

  const observableWorkflow = parseObservableResearchPipelineCommand(conversationalCandidate);
  if (observableWorkflow) {
    return {
      action: "run_job",
      payload: {
        title: `Observable research workflow: ${observableWorkflow.topic}`,
        objective: `Copy relevant docs sections about ${observableWorkflow.topic}, build a note, and compare topics.`,
        workflow: "observable_research_pipeline",
        workflow_args: observableWorkflow,
      },
    };
  }

  const conversationalOpenDocsMatch = conversationalCandidate.match(
    /^(?:(?:ok|okay)\s+)?(?:(?:can|could|would)\s+you\s+|please\s+)?(?:open(?:\s+up)?|show|pull\s+up|bring\s+up)\s+(?:(?:a|an|the)\s+)?(?:docs?|documentation|document|paper|report|publication|research)\b(?:\s+(?:about|for|on|regarding)\s+(.+?))?(?:\s+(?:and|then)\s+(.+))?[?.!]*$/i,
  );
  if (conversationalOpenDocsMatch) {
    const topic = conversationalOpenDocsMatch[1]?.trim() ?? "";
    const continuation = conversationalOpenDocsMatch[2]?.trim() ?? "";
    const hintedPath = resolveDocPathFromPrompt(topic || conversationalCandidate);
    const resolvedDoc = resolveDocOpenArgs(topic, hintedPath ?? "");
    const path = resolvedDoc?.path ?? "";
    const continuationWantsSummarize = /\b(?:summari[sz]e|summary|tldr|tl;dr)\b/i.test(continuation);
    const continuationWantsSectionSummary =
      continuationWantsSummarize && /\b(?:section|this\s+section|current\s+section|part)\b/i.test(continuation);
    const continuationWantsExplain = /\b(?:explain|break\s+down|walk\s+me\s+through|what\s+does)\b/i.test(
      continuation,
    );
    if (continuationWantsSummarize || continuationWantsExplain) {
      const fallbackPath = !path && topic
        ? (findBestDocForTopic(topic)?.route ?? findRandomPaperForTopic(topic)?.route ?? "/docs/papers.md")
        : "";
      const resolvedPath = path || fallbackPath;
      const resolutionArgs =
        resolvedDoc?.meta && resolvedPath
          ? {
              _doc_resolution_status: resolvedDoc.meta.status,
              _doc_resolution_confidence: resolvedDoc.meta.confidence,
              _doc_resolution_topic: resolvedDoc.meta.topic,
              _doc_resolution_candidates: resolvedDoc.meta.candidates,
            }
          : undefined;
      return {
        action: "run_panel_action",
        panel_id: "docs-viewer",
        action_id: continuationWantsSectionSummary
          ? "summarize_section"
          : continuationWantsExplain
            ? "explain_paper"
            : "summarize_doc",
        args: resolvedPath
          ? {
              path: resolvedPath,
              ...(resolutionArgs ?? {}),
            }
          : undefined,
      };
    }
    const readAloudRequested = /\b(?:read(?:\s+it)?(?:\s+out\s+loud|\s+aloud)?|out\s+loud|aloud|speak|narrate|voice)\b/i.test(
      conversationalCandidate,
    );
    if (path) {
      const resolutionArgs =
        resolvedDoc?.meta
          ? {
              _doc_resolution_status: resolvedDoc.meta.status,
              _doc_resolution_confidence: resolvedDoc.meta.confidence,
              _doc_resolution_topic: resolvedDoc.meta.topic,
              _doc_resolution_candidates: resolvedDoc.meta.candidates,
            }
          : undefined;
      return {
        action: "run_panel_action",
        panel_id: "docs-viewer",
        action_id: readAloudRequested ? "open_doc_and_read" : "open_doc",
        args: readAloudRequested
          ? { path, topic, ...(resolutionArgs ?? {}) }
          : { path, ...(resolutionArgs ?? {}) },
      };
    }
    return {
      action: "open_panel",
      panel_id: "docs-viewer",
    };
  }

  const conversationalOpenDocsDirectTopicMatch = conversationalCandidate.match(
    /^(?:(?:ok|okay)\s+)?(?:(?:can|could|would)\s+you\s+|please\s+)?(?:open(?:\s+up)?|show|pull\s+up|bring\s+up)\s+(?:(?:a|an|the)\s+)?(?:docs?|documentation|document|doc|paper|report|publication|research)\b\s+(.+?)(?:\s+(?:and|then)\s+(.+))?[?.!]*$/i,
  );
  if (conversationalOpenDocsDirectTopicMatch) {
    const topic = (conversationalOpenDocsDirectTopicMatch[1] ?? "")
      .replace(/^["'`“”]+|["'`“”]+$/g, "")
      .trim();
    const continuation = conversationalOpenDocsDirectTopicMatch[2]?.trim() ?? "";
    const hintedPath = resolveDocPathFromPrompt(topic || conversationalCandidate, {
      useTopicHints: false,
    });
    const resolvedDoc = resolveDocOpenArgs(topic, hintedPath ?? "");
    const fallbackPath = !resolvedDoc?.path && topic
      ? (findBestDocForTopic(topic)?.route ?? findRandomPaperForTopic(topic)?.route ?? "")
      : "";
    const resolvedPath = resolvedDoc?.path || fallbackPath;
    const resolutionArgs =
      resolvedDoc?.meta && resolvedPath
        ? {
            _doc_resolution_status: resolvedDoc.meta.status,
            _doc_resolution_confidence: resolvedDoc.meta.confidence,
            _doc_resolution_topic: resolvedDoc.meta.topic,
            _doc_resolution_candidates: resolvedDoc.meta.candidates,
          }
        : undefined;
    const continuationWantsSummarize = /\b(?:summari[sz]e|summary|tldr|tl;dr)\b/i.test(continuation);
    const continuationWantsSectionSummary =
      continuationWantsSummarize && /\b(?:section|this\s+section|current\s+section|part)\b/i.test(continuation);
    const continuationWantsExplain = /\b(?:explain|break\s+down|walk\s+me\s+through|what\s+does)\b/i.test(
      continuation,
    );
    if (continuationWantsSummarize || continuationWantsExplain) {
      return {
        action: "run_panel_action",
        panel_id: "docs-viewer",
        action_id: continuationWantsSectionSummary
          ? "summarize_section"
          : continuationWantsExplain
            ? "explain_paper"
            : "summarize_doc",
        args: resolvedPath
          ? {
              path: resolvedPath,
              ...(resolutionArgs ?? {}),
            }
          : undefined,
      };
    }
    const readAloudRequested = /\b(?:read(?:\s+it)?(?:\s+out\s+loud|\s+aloud)?|out\s+loud|aloud|speak|narrate|voice)\b/i.test(
      conversationalCandidate,
    );
    if (resolvedPath) {
      return {
        action: "run_panel_action",
        panel_id: "docs-viewer",
        action_id: readAloudRequested ? "open_doc_and_read" : "open_doc",
        args: readAloudRequested
          ? { path: resolvedPath, topic, ...(resolutionArgs ?? {}) }
          : { path: resolvedPath, ...(resolutionArgs ?? {}) },
      };
    }
    return {
      action: "open_panel",
      panel_id: "docs-viewer",
    };
  }

  const summarizeSectionRequested =
    /\b(?:summari[sz]e|summary|tldr|tl;dr)\b[\s\S]*\b(?:section|this\s+section|current\s+section|part)\b/i.test(
      conversationalCandidate,
    );
  if (summarizeSectionRequested) {
    const path = resolveDocPathFromPrompt(conversationalCandidate);
    return {
      action: "run_panel_action",
      panel_id: "docs-viewer",
      action_id: "summarize_section",
      args: path ? { path } : undefined,
    };
  }

  const summarizeDocRequested =
    /\b(?:summari[sz]e|summary|tldr|tl;dr)\b[\s\S]*\b(?:doc|document|paper|this\s+doc|this\s+document|this\s+paper|current\s+doc|current\s+document)\b/i.test(
      conversationalCandidate,
    );
  if (summarizeDocRequested) {
    const path = resolveDocPathFromPrompt(conversationalCandidate);
    return {
      action: "run_panel_action",
      panel_id: "docs-viewer",
      action_id: "summarize_doc",
      args: path ? { path } : undefined,
    };
  }

  const explainPaperRequested =
    /\b(?:explain|break\s+down|walk\s+me\s+through)\b[\s\S]*\b(?:paper|doc|document|this\s+paper|this\s+doc|this\s+document)\b/i.test(
      conversationalCandidate,
    );
  const docWhatIsRequested =
    /\b(?:what\s+(?:does|is)|tell\s+me|describe)\b[\s\S]*\b(?:this\s+doc|this\s+document|this\s+paper|the\s+doc|the\s+document|the\s+paper|doc|document|paper)\b[\s\S]*\b(?:do|about|say|mean)\b/i.test(
      conversationalCandidate,
    ) ||
    /\bwhat(?:'s|\s+is)\s+\b[\s\S]*\b(?:this\s+doc|this\s+document|this\s+paper)\b[\s\S]*\b(?:about)\b/i.test(
      conversationalCandidate,
    );
  if (explainPaperRequested || docWhatIsRequested) {
    const path = resolveDocPathFromPrompt(conversationalCandidate);
    return {
      action: "run_panel_action",
      panel_id: "docs-viewer",
      action_id: "explain_paper",
      args: path ? { path } : undefined,
    };
  }

  const deicticCurrentDocReadRequested =
    /\b(?:read|narrate|voice|aloud|out\s+loud)\b/i.test(conversationalCandidate) &&
    (/\b(?:this|current)\s+(?:doc|document|paper)\b/i.test(conversationalCandidate) ||
      (/\b(?:doc|document|paper)\b/i.test(conversationalCandidate) && /\bto\s+me\b/i.test(conversationalCandidate)));
  if (deicticCurrentDocReadRequested) {
    const hintedPath = resolveDocPathFromPrompt(conversationalCandidate);
    const activeDocPath = String(useDocViewerStore.getState().currentPath ?? "").trim();
    const resolvedPath = hintedPath || (activeDocPath ? normalizeDocsViewerAnchorPath(activeDocPath) : "");
    if (resolvedPath) {
      return {
        action: "run_panel_action",
        panel_id: "docs-viewer",
        action_id: "open_doc_and_read",
        args: { path: resolvedPath },
      };
    }
    return {
      action: "open_panel",
      panel_id: "docs-viewer",
    };
  }

  const latestDocRequestMatch = conversationalCandidate.match(
    /^(?:(?:ok|okay)\s+)?(?:(?:can|could|would)\s+you\s+|please\s+)?(?:pick|view|open|show|find|locate|pull\s+up|bring\s+up)\s+(?:(?:the|a|an)\s+)?(?:latest|newest|most\s+recent)\s+(.+?)\s+(?:doc|document|paper|report|publication)\b(?:\s+(?:from|for|on)\s+(?:today|this\s+week|this\s+month|\d{4}-\d{2}-\d{2}))?[?.!]*$/i,
  );
  if (latestDocRequestMatch) {
    const topic = latestDocRequestMatch[1]?.trim() ?? "";
    const resolution = topic ? resolveDocTopic(topic) : null;
    const best = resolution?.best ?? (topic ? findRandomPaperForTopic(topic) : null);
    const resolutionArgs =
      resolution && (resolution.status === "weak" || resolution.status === "ambiguous")
        ? {
            _doc_resolution_status: resolution.status,
            _doc_resolution_confidence: resolution.confidence,
            _doc_resolution_topic: topic || null,
            _doc_resolution_candidates: resolution.candidates.map((candidate) => candidate.route).filter((candidate) => Boolean(candidate)),
          }
        : undefined;
    const readAloudRequested = /\b(?:read|narrate|voice|aloud|out\s+loud)\b/i.test(conversationalCandidate);
    if (best?.route) {
      return {
        action: "run_panel_action",
        panel_id: "docs-viewer",
        action_id: readAloudRequested ? "open_doc_and_read" : "open_doc",
        args: readAloudRequested
          ? { path: best.route, topic, ...(resolutionArgs ?? {}) }
          : { path: best.route, ...(resolutionArgs ?? {}) },
      };
    }
    return {
      action: "open_panel",
      panel_id: "docs-viewer",
    };
  }

  const conversationalPaperRead = parsePaperReadCommand(conversationalCandidate);
  if (conversationalPaperRead) {
    const match = findRandomPaperForTopic(conversationalPaperRead.topic);
    return {
      action: "run_panel_action",
      panel_id: "docs-viewer",
      action_id: "open_doc_and_read",
      args: {
        path: match?.route ?? "/docs/papers.md",
        topic: conversationalPaperRead.topic,
      },
    };
  }

  const panelActionMatch = trimmed.match(/^\/panel-action\s+([a-z0-9._-]+)\s+([a-z0-9._-]+)(?:\s+(.+))?$/i);
  if (panelActionMatch) {
    const panelId = panelActionMatch[1]?.trim();
    const actionId = panelActionMatch[2]?.trim();
    const argsRaw = panelActionMatch[3]?.trim();
    let args: Record<string, unknown> | undefined;
    if (argsRaw) {
      try {
        const parsed = JSON.parse(argsRaw);
        if (parsed && typeof parsed === "object" && !Array.isArray(parsed)) {
          args = parsed as Record<string, unknown>;
        }
      } catch {
        args = { target: argsRaw };
      }
    }
    if (panelId && actionId) {
      return {
        action: "run_panel_action",
        panel_id: panelId,
        action_id: actionId,
        args,
      };
    }
  }

  const panelActionJsonMatch = trimmed.match(/^\/panel-action\s+(\{[\s\S]+\})$/i);
  if (panelActionJsonMatch) {
    try {
      const parsed = JSON.parse(panelActionJsonMatch[1]) as unknown;
      const actions = coerceHelixWorkstationActions(parsed).filter((action) => action.action === "run_panel_action");
      if (actions.length > 0) {
        return actions[0] ?? null;
      }
    } catch {
      // ignore malformed /panel-action JSON payloads
    }
  }

  const conversationalCloseCurrentPanel = new RegExp(
    [
      "^(?:",
      "/close-active-panel",
      "|/close-current-tab",
      "|close\\s+(?:all\\s+)?(?:the\\s+)?(?:open\\s+)?(?:tabs|panels)",
      "|close\\s+(?:my\\s+)?(?:tabs|panels)",
      "|close\\s+panels?",
      "|close\\s+(?:the\\s+)?(?:active|current|open)\\s+(?:tab|panel)",
      "|close\\s+(?:tab|panel)",
      "|close\\s+(?:the\\s+)?(?:doc|document|paper)(?:\\s+(?:for\\s+me|please))?",
      "|close\\s+(?:this|that)\\s+(?:tab|panel)(?:\\s+(?:for\\s+me|please))?",
      "|close\\s+(?:this|that|the\\s+current|current)\\s+(?:doc|document|paper)(?:\\s+(?:for\\s+me|please))?",
      "|close\\s+(?:whatever|whichever)\\s+(?:tab|panel)(?:\\s+i(?:'?m)?\\s+on)?",
      "|(?:shut|dismiss|remove|x\\s*out|get\\s+rid\\s+of)\\s+",
      "(?:(?:the\\s+)?(?:active|current|open|this|that)\\s+)?(?:tab|panel)(?:\\s+(?:for\\s+me|please))?",
      "|(?:shut|dismiss|remove|x\\s*out|get\\s+rid\\s+of)\\s+(?:(?:the\\s+)?(?:active|current|open|this|that)\\s+)?(?:doc|document|paper)(?:\\s+(?:for\\s+me|please))?",
      "|(?:shut|dismiss|remove|x\\s*out|get\\s+rid\\s+of)\\s+this\\s+panel(?:\\s+for\\s+me)?",
      ")$",
    ].join(""),
    "i",
  );
  if (conversationalCloseCurrentPanel.test(conversationalCommand)) {
    return { action: "close_active_panel" };
  }

  if (
    /^(?:\/next-tab|(?:go\s+to|switch\s+to|focus)?\s*next\s+(?:tab|panel))$/i.test(conversationalCommand)
  ) {
    return { action: "focus_next_panel" };
  }

  if (
    /^(?:\/prev-tab|\/previous-tab|(?:go\s+to|switch\s+to|focus)?\s*(?:previous|prev)\s+(?:tab|panel))$/i.test(
      conversationalCommand,
    )
  ) {
    return { action: "focus_previous_panel" };
  }

  if (
    /^(?:\/reopen-tab|reopen\s+(?:the\s+)?(?:last\s+)?closed\s+(?:tab|panel)|undo\s+close\s+(?:tab|panel))$/i.test(
      conversationalCommand,
    )
  ) {
    return { action: "reopen_last_closed_panel" };
  }

  const splitMatch = trimmed.match(/^(?:\/split|split)\s+(right|row|down|column)$/i);
  if (splitMatch) {
    return {
      action: "split_active_group",
      direction: /down|column/i.test(splitMatch[1]) ? "column" : "row",
    };
  }

  if (/^(?:\/settings|open settings|show settings)$/i.test(trimmed)) {
    return { action: "open_settings", tab: "preferences" };
  }

  if (/^(?:\/knowledge settings|open knowledge settings)$/i.test(trimmed)) {
    return { action: "open_settings", tab: "knowledge" };
  }

  if (/^(?:\/ask-dock collapse|collapse ask dock)$/i.test(trimmed)) {
    return { action: "set_chat_dock", collapsed: true };
  }

  if (/^(?:\/ask-dock expand|expand ask dock)$/i.test(trimmed)) {
    return { action: "set_chat_dock", collapsed: false };
  }

  if (/^(?:\/ask|open ask|show ask)$/i.test(trimmed)) {
    return { action: "toggle_mobile_drawer", open: true };
  }

  return null;
}

function buildHelixAskSearchQueries(question: string): string[] {
  const base = question.trim();
  if (!base) return [];
  const normalized = base.toLowerCase();
  const queries = [base];
  const seen = new Set([base.toLowerCase()]);
  const push = (value: string) => {
    const trimmed = value.trim();
    if (!trimmed) return;
    const key = trimmed.toLowerCase();
    if (seen.has(key)) return;
    seen.add(key);
    queries.push(trimmed);
  };

  if (/(scientific method|ask|assistant|llm|prompt|context|plan|execute|trace|code lattice|resonance)/i.test(normalized)) {
    push("/api/agi/ask");
    push("docs/helix-ask-flow.md");
    push("helix ask");
    push("helix ask flow");
    push("helix ask pipeline");
    push("buildGroundedAskPrompt");
    push("buildGroundedPrompt");
    push("askLocal");
    push("server/routes/agi.plan.ts");
    push("client/src/pages/desktop.tsx");
    push("client/src/components/helix/HelixAskPill.tsx");
    push("client/src/lib/agi/api.ts");
    push("server/skills/llm.local.spawn.ts");
  }
  if (normalized.includes("warp") || normalized.includes("alcubierre") || normalized.includes("bubble")) {
    push("warp bubble");
    push("modules/warp/warp-module.ts");
    push("calculateNatarioWarpBubble");
    push("warp pipeline");
    push("energy-pipeline warp");
  }
  if (normalized.includes("solve") || normalized.includes("solver")) {
    push("warp solver");
    push("constraint gate");
    push("gr evaluation");
  }

  return queries.slice(0, 6);
}

function buildGroundedPrompt(question: string, context: string): string {
  const formatSpec = decideHelixAskFormat(question);
  const lines = [
    "You are Helix Ask, a repo-grounded assistant.",
    "Use only the evidence in the context below. Cite file paths when referencing code.",
    "If the context is insufficient, say what is missing and ask a concise follow-up.",
    "When the context includes solver or calculation functions, summarize the inputs, outputs, and flow before UI details.",
  ];
  if (formatSpec.format === "steps") {
    lines.push("Start directly with a numbered list using `1.` style; use 6-9 steps and no preamble.");
    lines.push("Each step should be 2-3 sentences and grounded in repo details; cite file paths when relevant.");
    if (formatSpec.stageTags) {
      lines.push("Tag each step with the stage in parentheses (observe, hypothesis, experiment, analysis, explain).");
    } else {
      lines.push("Do not include stage tags or parenthetical labels unless explicitly requested.");
    }
    lines.push("After the steps, add a short paragraph starting with \"In practice,\" (2-3 sentences).");
  } else if (formatSpec.format === "compare") {
    lines.push("Answer in 2-3 short paragraphs; do not use numbered steps.");
    lines.push("If the question is comparative, include a short bullet list (3-5 items) of concrete differences grounded in repo details.");
    lines.push("Do not include stage tags or parenthetical labels unless explicitly requested.");
    lines.push("End with a short paragraph starting with \"In practice,\" (2-3 sentences).");
  } else {
    lines.push("Answer in 2-3 short paragraphs; do not use numbered steps unless explicitly requested.");
    lines.push("Do not include stage tags or parenthetical labels unless explicitly requested.");
    lines.push("End with a short paragraph starting with \"In practice,\" (2-3 sentences).");
  }
  lines.push("Avoid repetition; do not repeat any sentence or paragraph.");
  lines.push("Do not include the words \"Question:\" or \"Context sources\".");
  lines.push("Keep paragraphs short (2-3 sentences) and separate sections with blank lines.");
  lines.push("Do not repeat the question or include headings like Question, Context, or Resonance patch.");
  lines.push("Do not output tool logs, certificates, command transcripts, or repeat the prompt/context.");
  lines.push('Respond with only the answer and prefix it with "FINAL:".');
  lines.push("");
  lines.push(`Question: ${question}`);
  lines.push("");
  lines.push("Context:");
  lines.push(context || "No repo context was attached to this request.");
  lines.push("");
  lines.push("FINAL:");
  return lines.join("\n");
}

function buildGeneralPrompt(question: string): string {
  const formatSpec = decideHelixAskFormat(question);
  const lines = [
    "You are Helix Ask.",
    "Answer using general knowledge; do not cite file paths or repo details.",
  ];
  if (formatSpec.format === "steps") {
    lines.push("Start directly with a numbered list using `1.` style; use 4-6 steps and no preamble.");
    lines.push("Each step should be 1-2 sentences.");
    if (formatSpec.stageTags) {
      lines.push("Tag each step with the stage in parentheses (observe, hypothesis, experiment, analysis, explain).");
    } else {
      lines.push("Do not include stage tags or parenthetical labels unless explicitly requested.");
    }
    lines.push("After the steps, add a short paragraph starting with \"In practice,\" (1-2 sentences).");
  } else if (formatSpec.format === "compare") {
    lines.push("Answer in 1-2 short paragraphs; do not use numbered steps.");
    lines.push("If the question is comparative, include a short bullet list (2-4 items) of concrete differences.");
    lines.push("End with a short paragraph starting with \"In practice,\" (1-2 sentences).");
  } else {
    lines.push("Answer in 1-2 short paragraphs; do not use numbered steps unless explicitly requested.");
    lines.push("End with a short paragraph starting with \"In practice,\" (1-2 sentences).");
  }
  lines.push("Avoid repetition; do not repeat the question.");
  lines.push('Respond with only the answer and prefix it with "FINAL:".');
  lines.push("");
  lines.push(`Question: ${question}`);
  lines.push("");
  lines.push("FINAL:");
  return lines.join("\n");
}

function normalizeQuestionMatch(value: string): string {
  return value.toLowerCase().replace(/[^a-z0-9]+/g, " ").trim();
}

const QUESTION_PREFIX = /^question\s*:\s*/i;

function stripInlineQuestionLine(line: string, question?: string): string | null {
  if (!QUESTION_PREFIX.test(line)) return null;
  let rest = line.replace(QUESTION_PREFIX, "").trimStart();
  if (QUESTION_PREFIX.test(rest)) {
    rest = rest.replace(QUESTION_PREFIX, "").trimStart();
  }
  const questionTrimmed = question?.trim();
  if (questionTrimmed) {
    const questionLower = questionTrimmed.toLowerCase();
    if (rest.toLowerCase().startsWith(questionLower)) {
      rest = rest
        .slice(questionTrimmed.length)
        .replace(/^[\s:;,.!?-]+/, "")
        .trimStart();
    }
  }
  if (!rest) return "";
  const markIndex = rest.indexOf("?");
  if (markIndex >= 0 && markIndex < 240) {
    const after = rest.slice(markIndex + 1).replace(/^[\s:;,.!?-]+/, "").trimStart();
    if (after) return after;
  }
  return rest;
}

function stripQuestionPrefixText(value: string, question?: string): string {
  if (!value) return value;
  const lines = value.split(/\r?\n/);
  if (!lines.length) return value;
  const stripped = stripInlineQuestionLine(lines[0] ?? "", question);
  if (stripped === null) return value;
  if (stripped) {
    lines[0] = stripped;
  } else {
    lines.shift();
  }
  return lines.join("\n").trim();
}

function cleanPromptLine(value: string): string {
  if (!value) return "";
  const trimmed = value.trim();
  if (!trimmed) return "";
  const stripped = trimmed
    .replace(/^[\"'`.\-,;]+/g, "")
    .replace(/[\"'`.\-,;]+$/g, "")
    .trim();
  return stripped;
}

function stripLeadingQuestion(response: string, question?: string): string {
  const lines = response.split(/\r?\n/);
  const target = question?.trim();
  const targetNormalized = target ? normalizeQuestionMatch(target) : "";
  let startIndex = 0;
  while (startIndex < lines.length) {
    const inline = stripInlineQuestionLine(lines[startIndex] ?? "", question);
    if (inline !== null) {
      if (inline) {
        lines[startIndex] = inline;
        break;
      }
      startIndex += 1;
      continue;
    }
    const cleaned = cleanPromptLine(lines[startIndex]);
    if (!cleaned) {
      startIndex += 1;
      continue;
    }
    if (/^(question|context|resonance patch)\s*:/i.test(cleaned)) {
      startIndex += 1;
      continue;
    }
    if (target) {
      const lowerLine = cleaned.toLowerCase();
      if (lowerLine === target.toLowerCase()) {
        startIndex += 1;
        continue;
      }
      const normalizedLine = normalizeQuestionMatch(cleaned);
      if (normalizedLine && normalizedLine === targetNormalized) {
        startIndex += 1;
        continue;
      }
    }
    break;
  }
  return lines.slice(startIndex).join("\n").trim();
}

function stripPromptEcho(response: unknown, question?: string): string {
  let trimmed = stripQuestionPrefixText(coerceText(response).trim(), question);
  trimmed = stripLeadingQuestion(trimmed, question);
  trimmed = stripEvidencePromptBlock(trimmed);
  trimmed = stripAnswerBoundaryPrefix(trimmed);
  const answerBlock = extractAnswerBlock(trimmed);
  if (answerBlock) {
    return answerBlock;
  }
  if (!trimmed) return trimmed;
  const markers = ["FINAL:", "FINAL ANSWER:", "FINAL_ANSWER:", "Answer:"];
  for (const marker of markers) {
    const index = trimmed.lastIndexOf(marker);
    if (index >= 0) {
      const after = trimmed.slice(index + marker.length).trim();
      if (after) return after;
    }
  }
  const isScaffoldLine = (line: string) => {
    const cleaned = line
      .trim()
      .replace(/^[>"'`*#\-\d\.\)\s]+/, "")
      .trim();
    if (!cleaned) return true;
    const lowered = cleaned.toLowerCase();
    return (
      lowered.startsWith("you are helix ask") ||
      lowered.startsWith("use only the evidence") ||
      lowered.startsWith("use only the evidence steps") ||
      lowered.startsWith("use only the evidence bullets") ||
      lowered.startsWith("use general knowledge") ||
      lowered.startsWith("use only the reasoning") ||
      lowered.startsWith("revise the answer") ||
      lowered.startsWith("do not add new claims") ||
      lowered.startsWith("preserve the format") ||
      lowered.startsWith("keep the paragraph format") ||
      lowered.startsWith("keep the numbered step list") ||
      lowered.startsWith("use only file paths") ||
      lowered.startsWith("evidence:") ||
      lowered.startsWith("answer:") ||
      lowered.startsWith("if the context is insufficient") ||
      lowered.startsWith("if the question mentions") ||
      lowered.startsWith("when the context includes") ||
      lowered.startsWith("if the question is comparative") ||
      lowered.startsWith("answer in") ||
      lowered.startsWith("do not use numbered steps") ||
      lowered.startsWith("start directly with") ||
      lowered.startsWith("each step should") ||
      lowered.startsWith("after the steps") ||
      lowered.startsWith("avoid repetition") ||
      lowered.startsWith("preserve any stage tags") ||
      lowered.startsWith("do not include stage tags") ||
      lowered.startsWith("do not include the words") ||
      lowered.startsWith("do not output tool logs") ||
      lowered.startsWith("do not repeat the question") ||
      lowered.startsWith("end with a short paragraph") ||
      lowered.startsWith("respond with only the answer between") ||
      /^answer_(?:start|end)\b/i.test(cleaned) ||
      lowered.startsWith("no preamble") ||
      lowered.startsWith("no headings") ||
      lowered.startsWith("ask debug") ||
      lowered.startsWith("two-pass:") ||
      lowered.startsWith("format:") ||
      lowered.startsWith("stage tags:") ||
      lowered.startsWith("question:") ||
      lowered.includes("question:") ||
      lowered.startsWith("context:") ||
      lowered.startsWith("prompt context") ||
      lowered.startsWith("context sources") ||
      lowered.startsWith("resonance patch:") ||
      lowered.startsWith("knowledge projects:") ||
      lowered.startsWith("evidence steps:") ||
      lowered.startsWith("evidence bullets:") ||
      lowered.startsWith("reasoning steps:") ||
      lowered.startsWith("reasoning bullets:") ||
      lowered.startsWith("final:")
    );
  };
  const cleanedLines = trimmed
    .split(/\r?\n/)
    .filter((line) => !isScaffoldLine(line))
    .map((line) => stripAnswerBoundaryPrefix(line));
  const cleaned = cleanedLines.join("\n").trim();
  const formatSpec = decideHelixAskFormat(question);
  if (cleaned) {
    return formatSpec.stageTags ? cleaned : stripStageTags(cleaned);
  }
  return formatSpec.stageTags
    ? trimmed
    : stripStageTags(stripAnswerBoundaryPrefix(trimmed));
}

function extractAnswerBlock(value: string): string {
  if (!value) return "";
  const splitSegments = value
    .split(HELIX_ASK_ANSWER_MARKER_SPLIT_RE)
    .map((segment) => stripAnswerBoundaryPrefix(segment).trim())
    .filter(Boolean);
  if (splitSegments.length > 0) {
    const longest = splitSegments.reduce((best, candidate) =>
      best.length >= candidate.length ? best : candidate,
    "");
    if (longest) return longest;
  }
  const startIndex = value.lastIndexOf("ANSWER_START");
  if (startIndex >= 0) {
    const afterStart = value.slice(startIndex + "ANSWER_START".length);
    const endIndex = afterStart.lastIndexOf("ANSWER_END");
    const slice = endIndex >= 0 ? afterStart.slice(0, endIndex) : afterStart;
    const trimmed = stripAnswerBoundaryPrefix(slice).trim();
    if (trimmed) return trimmed;
  }
  const boundaryTrimmed = stripAnswerBoundaryPrefix(value);
  if (boundaryTrimmed) {
    return boundaryTrimmed;
  }
  const markers = ["FINAL:", "FINAL ANSWER:", "FINAL_ANSWER:", "Answer:"];
  for (const marker of markers) {
    const index = value.lastIndexOf(marker);
    if (index >= 0) {
      const after = value.slice(index + marker.length).trim();
      if (after) return after;
    }
  }
  return "";
}

function stripEvidencePromptBlock(value: string): string {
  if (!value) return value;
  const lines = value.split(/\r?\n/);
  const cleaned = lines.map((line) => cleanPromptLine(line));
  const evidenceIndex = cleaned.findIndex((line) => /^evidence\s*:/i.test(line));
  if (evidenceIndex < 0) return value;
  const answerIndex = cleaned.findIndex((line, index) => index > evidenceIndex && /^answer\s*:/i.test(line));
  if (answerIndex < 0) return value;
  const pruned = [...lines.slice(0, evidenceIndex), ...lines.slice(answerIndex + 1)];
  return pruned.join("\n").trim();
}

function parseSearchScore(preview: string | undefined): number {
  if (!preview) return 0;
  const match = preview.match(/score=([0-9.]+)/i);
  if (!match) return 0;
  const parsed = Number(match[1]);
  return Number.isFinite(parsed) ? parsed : 0;
}

function buildContextFromBundles(bundles: KnowledgeProjectExport[], question: string): string {
  const files = bundles.flatMap((bundle) => bundle.files ?? []);
  const helixAskFocus = HELIX_ASK_CORE_FOCUS.test(question);
  const scored = files
    .map((file) => {
      const label = file.path || file.name || "";
      const preview = file.preview ?? "";
      let score = parseSearchScore(preview);
      if (helixAskFocus) {
        if (HELIX_ASK_CORE_PATH_BOOST.test(label)) {
          score += 10;
        }
        if (HELIX_ASK_CORE_NOISE.test(label)) {
          score -= 6;
        }
      }
      if (HELIX_ASK_WARP_FOCUS.test(question) && HELIX_ASK_WARP_PATH_BOOST.test(label)) {
        score += 8;
      }
      return { file, label, preview, score };
    })
    .filter((entry) => entry.label && entry.preview && entry.score > 0)
    .sort((a, b) => b.score - a.score);

  const seen = new Set<string>();
  const lines: string[] = [];
  for (const entry of scored) {
    if (seen.has(entry.label)) continue;
    const preview = clipText(entry.preview, HELIX_ASK_CONTEXT_CHARS);
    if (!preview) continue;
    lines.push(`${entry.label}\n${preview}`);
    seen.add(entry.label);
    if (lines.length >= HELIX_ASK_CONTEXT_FILES) {
      return lines.join("\n\n");
    }
  }
  return lines.join("\n\n");
}

